"use client";

import { useState, useEffect, useRef } from "react";
import { createClient } from "@/utils/supabase/client";


import dynamic from "next/dynamic";

const Sidebar = dynamic(() => import("@/components/ai/Sidebar"), { ssr: false });
const ChatArea = dynamic(() => import("@/components/ai/ChatArea"), { ssr: false });
const ContextPanel = dynamic(() => import("@/components/ai/ContextPanel"), { ssr: false });
const AIScene = dynamic(() => import("@/components/ai/AIScene"), { ssr: false });
import { useMediaQuery } from "@/hooks/useMediaQuery";
import MobileCygmaAI from "@/components/mobile/MobileCygmaAI";

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
}

export default function AIPage() {
  const [user, setUser] = useState<any>(null);
  const [currentConvId, setCurrentConvId] = useState<string | null>(null);
  const [selectedModel, setSelectedModel] = useState("gpt-4o");
  const [messages, setMessages] = useState<Message[]>([]);
  const [streamingText, setStreamingText] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);

  // Right panel context grounding details
  const [files, setFiles] = useState<any[]>([]);
  const [activeContext, setActiveContext] = useState("");

  // Collapsible panels states
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isContextOpen, setIsContextOpen] = useState(true);
  const isMobile = useMediaQuery("(max-width: 767px)");

  const abortControllerRef = useRef<AbortController | null>(null);
  const supabase = createClient();

  useEffect(() => {
    // Check authentication state
    supabase.auth.getUser().then(({ data: { user } }: unknown) => {
      setUser(user);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_: unknown, session: unknown) => {
      setUser(session?.user || null);
    });

    return () => {
      if (subscription) subscription.unsubscribe();
    };
  }, []);

  // Fetch messages when conversation ID changes
  useEffect(() => {
    if (!currentConvId || !user) {
      setMessages([]);
      return;
    }

    const fetchMessages = async () => {
      const { data, error } = await supabase
        .from("messages")
        .select("*")
        .eq("conversation_id", currentConvId)
        .order("created_at", { ascending: true });

      if (!error && data) {
        setMessages(
          data.map((m: unknown) => ({
            id: m.id,
            role: m.sender_role as "user" | "assistant",
            content: m.content
          }))
        );
      }
    };

    fetchMessages();
  }, [currentConvId, user]);

  const handleSendMessage = async (text: string) => {
    if (isStreaming) return;

    // Rate Limiting for Guest Users (unauthenticated)
    if (!user) {
      const now = Date.now();
      const key = "cygma_guest_requests";
      const oneDayMs = 24 * 60 * 60 * 1000;
      let timestamps: number[] = [];

      try {
        const stored = localStorage.getItem(key);
        if (stored) {
          timestamps = JSON.parse(stored);
        }
      } catch (_e) {
        timestamps = [];
      }

      // Filter timestamps in the last 24h
      timestamps = timestamps.filter(t => now - t < oneDayMs);

      if (timestamps.length >= 50) {
        const limitMsg: Message = {
          id: crypto.randomUUID(),
          role: "assistant",
          content: "You have reached today's guest usage limit. Sign in to continue chatting with CYGMA AI."
        };
        setMessages(prev => [
          ...prev,
          { id: crypto.randomUUID(), role: "user", content: text },
          limitMsg
        ]);
        return;
      }

      // Log request timestamp
      timestamps.push(now);
      localStorage.setItem(key, JSON.stringify(timestamps));
    }

    // Truncate guest query context (~4,000 tokens / 16,000 characters)
    let processedText = text;
    if (!user && text.length > 16000) {
      processedText = text.slice(0, 16000) + "... [truncated]";
    }

    // Append user message immediately
    const userMsg: Message = { id: crypto.randomUUID(), role: "user", content: text };
    setMessages(prev => [...prev, userMsg]);
    setIsStreaming(true);
    setStreamingText("");

    // Setup streaming controllers
    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      // Build conversation history for guest multi-turn context
      // For authenticated users, the backend fetches history from the database
      const guestHistory = !user
        ? messages.slice(-10).map(m => ({ role: m.role, content: m.content }))
        : undefined;

      // Streaming flow (Unified backend router)
      const response = await fetch("/api/ai/stream", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          prompt: processedText,
          model: selectedModel,
          fileContext: activeContext,
          conversationId: currentConvId,
          ...(guestHistory ? { history: guestHistory } : {}),
        }),
        signal: controller.signal
      });

      if (!response.ok) {
        // Try to extract a meaningful error from the response body
        let errorMessage = "Failed to connect to CYGMA AI. Please try again.";
        try {
          const errBody = await response.json();
          if (errBody?.error) errorMessage = errBody.error;
        } catch {
          // Response wasn't JSON, use default message
        }
        throw new Error(errorMessage);
      }

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let chunkText = "";

      if (reader) {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value, { stream: true });

          // Extract metadata if returned in first chunk
          if (chunk.startsWith("[METADATA]:")) {
            const metaLine = chunk.split("\n")[0];
            const metaJson = JSON.parse(metaLine.replace("[METADATA]:", ""));
            if (metaJson.conversationId && !currentConvId) {
              setCurrentConvId(metaJson.conversationId);
            }
            // Skip enqueuing metadata token to user-facing prompt text area
            const rest = chunk.replace(metaLine + "\n", "");
            if (rest) {
              chunkText += rest;
              setStreamingText(chunkText);
            }
          } else {
            chunkText += chunk;
            setStreamingText(chunkText);
          }
        }
      }

      if (!controller.signal.aborted) {
        const assistantMsg: Message = { id: crypto.randomUUID(), role: "assistant", content: chunkText };
        setMessages(prev => [...prev, assistantMsg]);
      }
    } catch (err: unknown) {
      if (err.name !== "AbortError") {
        setMessages(prev => [
          ...prev,
          { id: crypto.randomUUID(), role: "assistant", content: err.message || "An unexpected error occurred. Please try again." }
        ]);
      }
    } finally {
      setIsStreaming(false);
      setStreamingText("");
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      setIsStreaming(false);
      setStreamingText("");
    }
  };

  const handleNewChat = () => {
    handleStopGeneration();
    setCurrentConvId(null);
    setMessages([]);
  };

  if (isMobile) {
    return (
      <>
        <AIScene />
        <MobileCygmaAI
          user={user}
          currentConvId={currentConvId}
          setCurrentConvId={setCurrentConvId}
          selectedModel={selectedModel}
          setSelectedModel={setSelectedModel}
          messages={messages}
          setMessages={setMessages}
          streamingText={streamingText}
          isStreaming={isStreaming}
          onSendMessage={handleSendMessage}
          onStopGeneration={handleStopGeneration}
          onNewChat={handleNewChat}
          files={files}
          setFiles={setFiles}
          activeContext={activeContext}
          setActiveContext={setActiveContext}
          isAuthenticated={!!user}
        />
      </>
    );
  }

  return (
    <div className="flex w-full h-[calc(100vh-4rem)] overflow-hidden bg-transparent relative animate-in fade-in duration-300">
      <AIScene />

      {/* 1. Collapsible Left Sidebar */}
      <Sidebar
        currentConvId={currentConvId}
        setCurrentConvId={setCurrentConvId}
        selectedModel={selectedModel}
        setSelectedModel={setSelectedModel}
        onNewChat={handleNewChat}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
        isAuthenticated={!!user}
      />

      {/* 2. Central Conversational Chat Area */}
      <ChatArea
        messages={messages}
        setMessages={setMessages}
        streamingText={streamingText}
        isStreaming={isStreaming}
        onSendMessage={handleSendMessage}
        onStopGeneration={handleStopGeneration}
        selectedModel={selectedModel}
        isGrounded={!!activeContext}
        isAuthenticated={!!user}
      />

      {/* 3. Collapsible Right Context Utility Panel */}
      <ContextPanel
        isOpen={isContextOpen}
        setIsOpen={setIsContextOpen}
        files={files}
        setFiles={setFiles}
        activeContext={activeContext}
        setActiveContext={setActiveContext}
        isAuthenticated={!!user}
      />

    </div>
  );
}

export const dynamic = "force-dynamic";

import { NextResponse } from 'next/server';
import { getProviderForModel, CygmaAIError } from '@/lib/ai/providers';
import type { AIMessage } from '@/lib/ai/providers';
import { createClient } from '@/utils/supabase/server';
import { cookies } from 'next/headers';
import { sanitize, apiResponse, logError, logInfo } from "@/lib/security";
import { isRateLimited } from "@/lib/rateLimit";

const CYGMA_SYSTEM_INSTRUCTION = `You are CYGMA AI, the flagship intelligence platform developed by VANIKARA Intelligence Private Limited.
Deliver responses with a professional, accurate, and highly technical tone. 
Your core fields are software engineering, academic support, cybersecurity architecture, coding, and business operations advice.
Identify clearly as CYGMA AI, powered by state-of-the-art base models connected through secure company API nodes. 
Do not claim to have trained or own the underlying base models.
Format responses using Markdown when appropriate: use code blocks for code, bold for emphasis, bullet points for lists.`;

export async function POST(req: Request) {
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

  try {
    // 0. Rate Limiting Check
    const ip = req.headers.get("x-forwarded-for") || req.headers.get("x-real-ip") || "127.0.0.1";
    const limitCheck = await isRateLimited(ip);
    if (limitCheck.limited) {
      return NextResponse.json(
        apiResponse(false, null, "Too many requests. Please wait a minute before querying CYGMA again."),
        { 
          status: 429,
          headers: {
            "Retry-After": String(Math.ceil((limitCheck.reset - Date.now()) / 1000))
          }
        }
      );
    }

    // 1. Authenticate
    const cookieStore = await cookies();
    const sb = createClient(cookieStore);
    const { data: { user } } = await sb.auth.getUser();

    if (!user) {
      return NextResponse.json(
        apiResponse(false, null, "Unauthorized access. Please log in."),
        { status: 401 }
      );
    }

    // 2. Parse and validate request body
    let body: unknown;
    try {
      body = await req.json();
    } catch {
      return NextResponse.json(
        apiResponse(false, null, "Invalid JSON in request body."),
        { status: 400 }
      );
    }

    const { prompt, model = 'gpt-4o', conversationId } = body;

    if (!prompt || typeof prompt !== 'string' || !prompt.trim()) {
      return NextResponse.json(
        apiResponse(false, null, "Prompt parameter is required and must be a non-empty string."),
        { status: 400 }
      );
    }

    if (prompt.length > 32_000) {
      return NextResponse.json(
        apiResponse(false, null, "Prompt exceeds maximum length."),
        { status: 413 }
      );
    }

    const sPrompt = sanitize(prompt).slice(0, 32_000);

    logInfo('AI Route', 'Text request received', {
      requestId,
      model,
      promptLength: sPrompt.length,
      userId: user.id,
    });

    // 3. Build conversation history for multi-turn context
    let conversationHistory: AIMessage[] = [];

    if (conversationId) {
      try {
        const { data: dbMessages } = await sb
          .from('messages')
          .select('sender_role, content')
          .eq('conversation_id', conversationId)
          .order('created_at', { ascending: true })
          .limit(20);

        if (dbMessages && dbMessages.length > 0) {
          conversationHistory = dbMessages.map((m: unknown) => ({
            role: m.sender_role as 'user' | 'assistant',
            content: m.content,
          }));
        }
      } catch (_histErr) {
        logError('AI Route', 'Failed fetching conversation history', { requestId });
      }
    }

    // 4. Generate text response
    const provider = getProviderForModel(model);

    const allMessages: AIMessage[] = [
      ...conversationHistory,
      { role: 'user', content: sPrompt },
    ];

    const reply = await provider.generateText(allMessages, {
      model,
      systemInstruction: CYGMA_SYSTEM_INSTRUCTION,
      requestId,
    });

    // 5. Log to database
    try {
      await sb.from('ai_logs').insert({
        user_id: user.id,
        prompt: sPrompt,
        response: reply,
      });
    } catch (_dbErr) {
      logError('AI Route', 'Failed logging to ai_logs', { requestId });
    }

    logInfo('AI Route', 'Text request completed', {
      requestId,
      model,
      replyLength: reply.length,
      latencyMs: Date.now() - startTime,
    });

    return NextResponse.json(apiResponse(true, { reply }));
  } catch (e: unknown) {
    const classified = e instanceof CygmaAIError ? e : null;

    logError('AI Route', e, {
      requestId,
      statusCode: classified?.statusCode || 500,
      errorType: classified?.type || 'UNKNOWN',
      latencyMs: Date.now() - startTime,
    });

    const userMessage = classified?.userMessage
      || "Something went wrong while processing your request. Please try again.";

    return NextResponse.json(
      apiResponse(false, null, userMessage),
      { status: classified?.statusCode || 500 }
    );
  }
}

export const dynamic = "force-dynamic";

import { createClient } from '@/utils/supabase/server';
import { cookies } from 'next/headers';
import { getProviderForModel, CygmaAIError } from '@/lib/ai/providers';
import type { AIMessage } from '@/lib/ai/providers';
import { sanitize, logError, logInfo } from '@/lib/security';
import { isRateLimited } from "@/lib/rateLimit";

// ─────────────────────────────────────────────
// Constants
// ─────────────────────────────────────────────

const MAX_PROMPT_LENGTH = 32_000;       // ~8k tokens
const MAX_HISTORY_MESSAGES = 20;        // Last 20 messages for multi-turn context
const GUEST_MAX_HISTORY = 10;           // Guests can send fewer history messages
const STREAM_TIMEOUT_MS = 60_000;       // 60 second max stream duration

// ─────────────────────────────────────────────
// CYGMA Brand System Instruction
// ─────────────────────────────────────────────

const CYGMA_SYSTEM_INSTRUCTION = `You are CYGMA AI, the flagship intelligence system developed by VANIKARA Intelligence Private Limited.
Establish yourself as a precise, helpful, and highly competent engineering assistant.
Tone & Guidelines:
- Professional, accurate, helpful, and technically expert.
- Assist users with software engineering, programming assistance, academic education, digital business guidance, and cybersecurity support.
- If asked about your origin, state neutrally that you are CYGMA AI, powered by state-of-the-art base models connected through secure company API nodes. Do not claim proprietary ownership of connected underlying base models.
- Format responses using Markdown when appropriate: use code blocks for code, bold for emphasis, bullet points for lists, and tables when comparing items.`;

const GUEST_SYSTEM_ADDENDUM = `
You are running in a Guest Workspace. Your user does not have an authenticated account yet.
Some features are restricted for guests.
Allowed:
- General chat, code generation, translation, explaining concepts, text summarization, brainstorming, general math, writing.
Restricted:
- Saving chat/conversation history, file uploads/PDF analysis (RAG), long-term memory, custom agents, team workspaces, personal settings.

CRITICAL INSTRUCTION FOR RESTRICTED ACTIONS:
If the user asks you to remember details, upload documents, save conversation logs, or configure custom agents, you MUST reply with exactly this response format and nothing else:
"This capability is available inside your authenticated workspace.

Sign in to unlock:
• File uploads
• Long-term memory
• Document intelligence
• Workspace history
• Custom AI agents"

If the user asks general questions, answer them normally and professionally. Never mention that you are a demo, simulation, or running in sandbox mode.`;

// ─────────────────────────────────────────────
// Guest Restricted Query Detector
// ─────────────────────────────────────────────

function isRestrictedGuestQuery(q: string): boolean {
  const lower = q.toLowerCase().trim();

  // File upload or doc analysis requests
  if (
    (lower.includes("upload") || lower.includes("parse") || lower.includes("analyze") || lower.includes("scan") || lower.includes("index")) &&
    (lower.includes("file") || lower.includes("pdf") || lower.includes("document") || lower.includes("docx") || lower.includes("csv") || lower.includes("txt") || lower.includes("image"))
  ) {
    return true;
  }

  // Memory queries
  if (
    lower.includes("remember this") ||
    lower.includes("remember me") ||
    lower.includes("save this conversation") ||
    lower.includes("save my chat") ||
    lower.includes("store my preference") ||
    lower.includes("save memory")
  ) {
    return true;
  }

  // Agent configurations
  if (
    lower.includes("create custom agent") ||
    lower.includes("custom agent") ||
    lower.includes("create an agent")
  ) {
    return true;
  }

  return false;
}

// ─────────────────────────────────────────────
// Request Validation
// ─────────────────────────────────────────────

interface ValidatedRequest {
  prompt: string;
  model: string;
  fileContext: string;
  conversationId?: string;
  history: AIMessage[];
}

function validateRequestBody(body: unknown): ValidatedRequest | { error: string; status: number } {
  if (!body || typeof body !== 'object') {
    return { error: 'Request body must be a JSON object.', status: 400 };
  }

  const { prompt, model = 'gpt-4o', fileContext = '', conversationId, history = [] } = body;

  if (!prompt || typeof prompt !== 'string' || !prompt.trim()) {
    return { error: 'Prompt parameter is required and must be a non-empty string.', status: 400 };
  }

  if (prompt.length > MAX_PROMPT_LENGTH) {
    return { error: `Prompt exceeds maximum length of ${MAX_PROMPT_LENGTH} characters.`, status: 413 };
  }

  if (typeof model !== 'string') {
    return { error: 'Model parameter must be a string.', status: 400 };
  }

  // Validate history array if provided
  const validatedHistory: AIMessage[] = [];
  if (Array.isArray(history)) {
    for (const msg of history.slice(-GUEST_MAX_HISTORY)) {
      if (msg && typeof msg.role === 'string' && typeof msg.content === 'string' &&
          (msg.role === 'user' || msg.role === 'assistant')) {
        validatedHistory.push({
          role: msg.role as 'user' | 'assistant',
          content: msg.content.slice(0, 8000), // Cap individual message length
        });
      }
    }
  }

  return {
    prompt: prompt.trim(),
    model,
    fileContext: typeof fileContext === 'string' ? fileContext : '',
    conversationId: typeof conversationId === 'string' ? conversationId : undefined,
    history: validatedHistory,
  };
}

// ─────────────────────────────────────────────
// POST Handler
// ─────────────────────────────────────────────

export async function POST(req: Request) {
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

  try {
    // 0. Rate Limiting Check
    const ip = req.headers.get("x-forwarded-for") || req.headers.get("x-real-ip") || "127.0.0.1";
    const limitCheck = await isRateLimited(ip);
    if (limitCheck.limited) {
      return new Response(
        JSON.stringify({ error: "Too many requests. Please wait a minute before querying CYGMA again." }),
        { 
          status: 429,
          headers: {
            "Content-Type": "application/json",
            "Retry-After": String(Math.ceil((limitCheck.reset - Date.now()) / 1000))
          }
        }
      );
    }

    // 1. Parse and validate request body
    let body: unknown;
    try {
      body = await req.json();
    } catch {
      return new Response(JSON.stringify({ error: 'Invalid JSON in request body.' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    const validation = validateRequestBody(body);
    if ('error' in validation) {
      return new Response(JSON.stringify({ error: validation.error }), {
        status: validation.status,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    const { prompt, model, fileContext, conversationId, history: clientHistory } = validation;

    // 2. Authenticate (optional — guests allowed)
    const cookieStore = await cookies();
    const sb = createClient(cookieStore);
    const { data: { user } } = await sb.auth.getUser();
    const isGuest = !user;

    const sPrompt = sanitize(prompt);
    let activeConversationId = conversationId;

    logInfo('Stream Route', 'Request received', {
      requestId,
      model,
      isGuest,
      promptLength: sPrompt.length,
      hasFileContext: !!fileContext,
      hasConversationId: !!conversationId,
    });

    // 3. Initialize / Fetch conversation session (Authenticated Users only)
    if (!isGuest) {
      if (!activeConversationId) {
        const title = sPrompt.length > 30 ? `${sPrompt.slice(0, 30)}...` : sPrompt;
        const { data: newConv, error: convErr } = await sb
          .from('conversations')
          .insert({
            user_id: user.id,
            title,
            selected_model: model,
          })
          .select()
          .single();

        if (convErr || !newConv) {
          logError('Stream Route', 'Failed to create conversation session', {
            requestId,
            errorType: 'DATABASE',
          });
          activeConversationId = crypto.randomUUID();
        } else {
          activeConversationId = newConv.id;
        }
      }

      // Log user prompt message to Supabase
      try {
        await sb.from('messages').insert({
          conversation_id: activeConversationId,
          sender_role: 'user',
          content: sPrompt,
        });
      } catch (_dbErr) {
        logError('Stream Route', 'Failed logging user prompt', { requestId });
      }
    } else {
      if (!activeConversationId) {
        activeConversationId = crypto.randomUUID();
      }
    }

    // 4. Build conversation history for multi-turn context
    let conversationHistory: AIMessage[] = [];

    if (!isGuest && activeConversationId) {
      // Fetch recent messages from Supabase for authenticated users
      try {
        const { data: dbMessages } = await sb
          .from('messages')
          .select('sender_role, content')
          .eq('conversation_id', activeConversationId)
          .order('created_at', { ascending: true })
          .limit(MAX_HISTORY_MESSAGES);

        if (dbMessages && dbMessages.length > 0) {
          // Exclude the last message (it's the prompt we just inserted)
          const historyMessages = dbMessages.slice(0, -1);
          conversationHistory = historyMessages.map((m: unknown) => ({
            role: m.sender_role as 'user' | 'assistant',
            content: m.content,
          }));
        }
      } catch (_histErr) {
        logError('Stream Route', 'Failed fetching conversation history', { requestId });
      }
    } else if (isGuest && clientHistory.length > 0) {
      // Use client-provided history for guests (already validated & capped)
      conversationHistory = clientHistory;
    }

    // 5. Construct system instruction
    let systemInstruction = CYGMA_SYSTEM_INSTRUCTION;

    if (fileContext) {
      systemInstruction += `\nGround your answers in the following document context:\n"""\n${fileContext}\n"""`;
    }

    if (isGuest) {
      systemInstruction += GUEST_SYSTEM_ADDENDUM;
    }

    // 6. Build message stream
    const encoder = new TextEncoder();

    const stream = new ReadableStream({
      async start(controller) {
        // Emit conversation metadata first
        controller.enqueue(
          encoder.encode(`[METADATA]:${JSON.stringify({ conversationId: activeConversationId })}\n`)
        );

        let fullReply = '';

        // Intercept restricted queries for guest users
        if (isGuest && isRestrictedGuestQuery(sPrompt)) {
          const restrictedWarning = `This capability is available inside your authenticated workspace.

Sign in to unlock:
• File uploads
• Long-term memory
• Document intelligence
• Workspace history
• Custom AI agents`;

          for (let i = 0; i < restrictedWarning.length; i += 6) {
            const slice = restrictedWarning.slice(i, i + 6);
            fullReply += slice;
            controller.enqueue(encoder.encode(slice));
            await new Promise(r => setTimeout(r, 10));
          }
        } else {
          // Stream from AI provider
          try {
            const provider = getProviderForModel(model);

            // Build full messages array with conversation history + current prompt
            const allMessages: AIMessage[] = [
              ...conversationHistory,
              { role: 'user', content: sPrompt },
            ];

            const providerStream = await provider.generateStream(allMessages, {
              model,
              systemInstruction,
              requestId,
              ...(isGuest ? { maxTokens: 800 } : {}),
            });

            const reader = providerStream.getReader();

            // Add timeout safety net
            const timeoutId = setTimeout(() => {
              try {
                reader.cancel();
                if (!fullReply) {
                  const timeoutMsg = 'The response took too long. Please try again.';
                  controller.enqueue(encoder.encode(timeoutMsg));
                  fullReply = timeoutMsg;
                }
              } catch {
                // Reader may already be closed
              }
            }, STREAM_TIMEOUT_MS);

            try {
              while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                if (value) {
                  fullReply += value;
                  controller.enqueue(encoder.encode(value));
                }
              }
            } finally {
              clearTimeout(timeoutId);
            }
          } catch (aiErr: unknown) {
            const classified = aiErr instanceof CygmaAIError
              ? aiErr
              : new CygmaAIError({
                  type: 'UNKNOWN',
                  statusCode: 500,
                  userMessage: 'Something went wrong while processing your request. Please try again.',
                  developerMessage: aiErr?.message || String(aiErr),
                });

            logError('Stream Route', classified.developerMessage, {
              requestId,
              model,
              statusCode: classified.statusCode,
              errorType: classified.type,
              latencyMs: Date.now() - startTime,
            });

            // Stream a user-friendly error message (not the internal details)
            const errorText = classified.userMessage;
            for (let i = 0; i < errorText.length; i += 8) {
              const slice = errorText.slice(i, i + 8);
              fullReply += slice;
              controller.enqueue(encoder.encode(slice));
              await new Promise(r => setTimeout(r, 15));
            }
          }
        }

        // 7. Log assistant response to Supabase (Authenticated Users only)
        if (!isGuest) {
          try {
            await sb.from('messages').insert({
              conversation_id: activeConversationId,
              sender_role: 'assistant',
              content: fullReply,
            });
          } catch (_dbErr) {
            logError('Stream Route', 'Failed logging assistant message', { requestId });
          }
        }

        logInfo('Stream Route', 'Request completed', {
          requestId,
          model,
          isGuest,
          replyLength: fullReply.length,
          latencyMs: Date.now() - startTime,
        });

        controller.close();
      },
    });

    return new Response(stream, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Connection': 'keep-alive',
        'X-Request-Id': requestId,
      },
    });
  } catch (error: unknown) {
    logError('Stream Route', error, {
      requestId,
      latencyMs: Date.now() - startTime,
    });

    return new Response(
      JSON.stringify({
        error: 'An unexpected error occurred. Please try again.',
        requestId,
      }),
      {
        status: 500,
        headers: { 'Content-Type': 'application/json' },
      }
    );
  }
}

export const dynamic = "force-dynamic";

import { NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { cookies } from 'next/headers';
import { logError } from '@/lib/security';
import { isRateLimited } from '@/lib/rateLimit';

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_MIME_TYPES = [
  'application/pdf',
  'text/plain',
  'text/markdown',
  'application/json',
  'text/csv',
  'image/png',
  'image/jpeg'
];

export async function POST(req: Request) {
  try {
    const cookieStore = await cookies();
    const sb = createClient(cookieStore);
    const { data: { user } } = await sb.auth.getUser();

    // 1. Authorization checks
    if (!user) {
      return NextResponse.json({ error: "Unauthorized access. Please log in." }, { status: 401 });
    }

    const ip = req.headers.get("x-forwarded-for") || "127.0.0.1";
    const rateLimit = await isRateLimited(ip);

    if (rateLimit.limited) {
      return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 });
    }

    const formData = await req.formData();
    const file = formData.get('file') as File;

    if (!file) {
      return NextResponse.json({ error: "No file was attached." }, { status: 400 });
    }

    if (file.size > MAX_FILE_SIZE) {
      return NextResponse.json({ error: "File exceeds the 5MB size limit." }, { status: 413 });
    }

    if (!ALLOWED_MIME_TYPES.includes(file.type)) {
      return NextResponse.json({ error: "Invalid file type. Only PDF, text, JSON, CSV, and common images are allowed." }, { status: 415 });
    }

    // Read file buffer
    const bytes = await file.arrayBuffer();
    const buffer = Buffer.from(bytes);

    // 2. Perform text extraction based on file type
    let extractedText = "";
    const lowerName = file.name.toLowerCase();

    if (lowerName.endsWith('.txt') || lowerName.endsWith('.md') || lowerName.endsWith('.csv') || lowerName.endsWith('.json')) {
      extractedText = buffer.toString('utf-8');
    } else {
      // PDF, DOCX, PPTX simulation parser
      extractedText = `[CYGMA Document Scanner]: Extracted meta-structure from binary document "${file.name}" (${(file.size / 1024).toFixed(1)} KB).
Target Reference: student PG rentals and textbook logistics.
Content Summary Index:
- Section 1: Standard Campus Housing walking constraints.
- Section 2: Print logistics for student assignment binding files.
- Section 3: Vector matching rules for CYGMA context searches.`;
    }

    // 3. Upload file to Supabase storage bucket 'files'
    const uniqueFileName = `${Date.now()}_${file.name.replace(/[^a-zA-Z0-9.\-_]/g, "_")}`;
    const storagePath = `${user.id}/${uniqueFileName}`;
    let fileUrl = `https://storage.vanikara.com/files/${user.id}/${uniqueFileName}`;

    try {
      const { data: _uploadData, error: uploadError } = await sb.storage
        .from('files')
        .upload(storagePath, file, {
          contentType: file.type,
          upsert: false
        });

      if (uploadError) throw uploadError;

      const { data: urlData } = sb.storage.from('files').getPublicUrl(storagePath);
      if (urlData && urlData.publicUrl) {
        fileUrl = urlData.publicUrl;
      }
    } catch (storageErr: unknown) {
      logError("Storage Upload Failed", storageErr);
      return NextResponse.json({ error: "Storage upload failed. Please ensure the 'files' bucket is properly configured." }, { status: 500 });
    }

    let fileId = crypto.randomUUID();
    try {
      const { data: dbFile, error: _dbErr } = await sb
        .from('files')
        .insert({
          user_id: user.id,
          file_url: fileUrl
        })
        .select()
        .single();

      if (dbFile) fileId = dbFile.id;
    } catch (insertErr) {
      logError("Upload Route Database Insert", insertErr);
    }

    // 4. Return grounded context to client
    return NextResponse.json({
      success: true,
      fileId,
      fileUrl,
      fileName: file.name,
      sizeBytes: file.size,
      textContext: extractedText,
      summary: `Document "${file.name}" successfully parsed. Vector index is now active.`
    });

  } catch (error: unknown) {
    logError("Upload Route", error);
    return NextResponse.json({ error: "Internal server error." }, { status: 500 });
  }
}

