import { NextResponse } from "next/server";
import { supabaseService } from "@/utils/supabase/service";
import { createClient } from "@/utils/supabase/server";
import { cookies } from "next/headers";
import { isAdmin } from "@/lib/isAdmin";
import nodemailer from "nodemailer";
import { logError } from "@/lib/security";

export const dynamic = "force-dynamic";

let cachedStatus: unknown = null;
let lastCheckTime = 0;
const CACHE_TTL_MS = 60000; // Cache health status checks for 60 seconds

export async function GET() {
  const now = Date.now();

  // 1. Resolve User and Admin status
  let isUserAdmin = false;
  try {
    const cookieStore = await cookies();
    const sb = createClient(cookieStore);
    const { data: { user } } = await sb.auth.getUser();
    if (user && isAdmin(user)) {
      isUserAdmin = true;
    }
  } catch (_authErr) {
    // Fail silent, treat as anonymous
  }

  // If request is anonymous or regular user, return a simple health status immediately
  if (!isUserAdmin) {
    return NextResponse.json({
      status: "healthy",
      timestamp: new Date().toISOString()
    });
  }

  // 2. Perform detailed checks for Admin
  if (cachedStatus && now - lastCheckTime < CACHE_TTL_MS) {
    return NextResponse.json(
      {
        ...cachedStatus,
        timestamp: new Date().toISOString(),
        cached: true,
      },
      { status: cachedStatus.status === "healthy" ? 200 : 500 }
    );
  }

  const status: Record<string, unknown> = {
    status: "healthy",
    timestamp: new Date().toISOString(),
    services: {
      database: "healthy",
      openai: "healthy",
      email: "healthy"
    }
  };

  let hasError = false;

  // 1. Check Database connectivity via Supabase service client
  try {
    const { error } = await supabaseService.from("leads").select("id").limit(1);
    if (error) {
      status.services.database = `unhealthy: ${error.message}`;
      hasError = true;
    }
  } catch (err: unknown) {
    status.services.database = `unhealthy: ${err.message}`;
    hasError = true;
  }

  // 2. Check OpenAI configuration credentials
  if (!process.env.OPENAI_API_KEY) {
    status.services.openai = "unhealthy: OPENAI_API_KEY is not configured";
    hasError = true;
  } else if (!process.env.OPENAI_API_KEY.startsWith("sk-")) {
    status.services.openai = "unhealthy: OPENAI_API_KEY has an invalid key format";
    hasError = true;
  }

  // 3. Check Nodemailer SMTP configuration
  if (!process.env.SMTP_HOST || !process.env.SMTP_USER || !process.env.SMTP_PASS) {
    status.services.email = "disabled: SMTP authentication environment variables not configured";
  } else {
    try {
      const transporter = nodemailer.createTransport({
        host: process.env.SMTP_HOST,
        port: Number(process.env.SMTP_PORT) || 587,
        auth: {
          user: process.env.SMTP_USER,
          pass: process.env.SMTP_PASS,
        },
      });
      // Verifies connection configuration and SMTP credentials
      await transporter.verify();
    } catch (err: unknown) {
      status.services.email = `unhealthy: SMTP verification failed - ${err.message}`;
      hasError = true;
    }
  }

  if (hasError) {
    status.status = "unhealthy";
    logError("Health Check", "System health check degraded", { errorType: "health_degraded" });
  }

  // Save to cache
  cachedStatus = { ...status };
  lastCheckTime = now;

  return NextResponse.json(status, { status: hasError ? 500 : 200 });
}

import { NextResponse } from "next/server";
import { promises as fs } from "fs";
import path from "path";
import { supabaseService } from "@/utils/supabase/service";

const STATIC_PATH = path.join(process.cwd(), "data/privacy_config.json");

async function getConfig() {
  try {
    const { data, error } = await supabaseService
      .from("privacy_config")
      .select("*")
      .eq("id", 1)
      .maybeSingle();

    if (data && !error) {
      return {
        currentVersion: data.current_version,
        policyText: data.policy_text,
        optionalServices: data.optional_services,
        stats: data.stats,
      };
    }
  } catch (err) {
    console.warn("Database check failed in consent, falling back to local file. Error:", err);
  }

  try {
    const fileContent = await fs.readFile(STATIC_PATH, "utf-8");
    return JSON.parse(fileContent);
  } catch (err) {
    console.error("Failed to read static fallback privacy_config file in consent:", err);
    return {
      currentVersion: "1.0.0",
      policyText: "We use essential cookies to operate our website and optional cookies.",
      stats: {
        totalVisits: 0,
        acceptedAll: 0,
        rejectedOptional: 0,
        customized: 0,
        analyticsAccepted: 0,
        marketingAccepted: 0,
        preferencesAccepted: 0
      },
      optionalServices: {
        googleAnalytics: true,
        facebookPixel: false,
        hotjar: false
      }
    };
  }
}

export async function POST(req: Request) {
  try {
    const { action, preferences, _version } = await req.json();

    // 1. Read existing config
    const config = await getConfig();

    // 2. Increment aggregate stats based on user choice
    config.stats.totalVisits += 1;

    if (action === "accept_all") {
      config.stats.acceptedAll += 1;
      config.stats.analyticsAccepted += 1;
      config.stats.marketingAccepted += 1;
      config.stats.preferencesAccepted += 1;
    } else if (action === "reject_optional") {
      config.stats.rejectedOptional += 1;
    } else {
      config.stats.customized += 1;
      if (preferences?.analytics) config.stats.analyticsAccepted += 1;
      if (preferences?.marketing) config.stats.marketingAccepted += 1;
      if (preferences?.preferences) config.stats.preferencesAccepted += 1;
    }

    try {
      // 3. Try to save updated stats to Supabase database
      const { error } = await supabaseService
        .from("privacy_config")
        .upsert({
          id: 1,
          current_version: config.currentVersion,
          policy_text: config.policyText,
          optional_services: config.optionalServices,
          stats: config.stats,
          updated_at: new Date().toISOString(),
        });

      if (error) throw error;
    } catch (dbErr) {
      console.warn("Failed to write updated stats to database, falling back to local file. Error:", dbErr);
    }

    return NextResponse.json({ success: true });
  } catch (error: unknown) {
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

"use client";

import React, { useState } from "react";
import PageHero from "@/components/ui/PageHero";
import Card, { CardBody } from "@/components/ui/Card";
