"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { 
  User, 
  Settings, 
  LogOut, 
  Compass, 
  Layers,
  _Sparkles,
  ArrowRight,
  ShieldCheck,
  Zap,
  MessageSquare,
  Lock,
  RefreshCw,
  Check,
  Bell,
  Info,
  Key
} from "lucide-react";
import { createClient } from "@/utils/supabase/client";
import Button from "@/components/ui/Button";
import Card, { CardBody } from "@/components/ui/Card";
import { useTheme } from "@/components/layout/ThemeContext";
import DashboardScene from "@/components/dashboard/DashboardScene";

export default function DashboardClient({ initialUser, initialProfile, initialSub }: unknown) {
  const [activeTab, setActiveTab] = useState("overview");
  const [user, _setUser] = useState(initialUser);
  const [sub, setSub] = useState(initialSub);
  const [profile, setProfile] = useState(initialProfile || { name: "", email: "" });
  const [conversations, setConversations] = useState<any[]>([]);
  const [upgrading, setUpgrading] = useState(false);
  const [savingProfile, setSavingProfile] = useState(false);
  const [profileMsg, setProfileMsg] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [savingPassword, setSavingPassword] = useState(false);
  const [passwordMsg, setPasswordMsg] = useState("");

  // Theme states
  const { theme, resolvedTheme, atmosphere, setTheme } = useTheme();

  // Notifications Mock/DB
  const [notifications, _setNotifications] = useState<any[]>([
    { id: 1, title: "System Initialized", message: "Welcome to the VANIKARA Digital Portal. Cygma AI sandbox node is now active.", type: "info", time: "Just now" },
    { id: 2, title: "Registry Timestamp Sync", message: "Successfully synced profile database records to primary pgvector cluster.", type: "success", time: "1 hour ago" },
    { id: 3, title: "Starter Plan Active", message: "Starter account trial initialized. You have 16 days of full access remaining.", type: "warning", time: "1 day ago" }
  ]);

  const supabase = createClient();
  const router = useRouter();

  useEffect(() => {
    if (activeTab === "chats" && user) {
      // Fetch saved conversations
      supabase
        .from("conversations")
        .select("*")
        .order("created_at", { ascending: false })
        .then(({ data }: unknown) => {
          setConversations(data || []);
        });
    }
  }, [activeTab, user]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    router.push("/");
  };

  const handleSaveProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingProfile(true);
    setProfileMsg("");
    try {
      const { error } = await supabase
        .from("users")
        .update({ name: profile.name })
        .eq("id", user.id);
      if (error) throw error;
      setProfileMsg("Profile updated successfully!");
    } catch (err: unknown) {
      setProfileMsg(`Failed to save: ${err.message}`);
    } finally {
      setSavingProfile(false);
    }
  };

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPassword) return;
    setSavingPassword(true);
    setPasswordMsg("");
    try {
      const { error } = await supabase.auth.updateUser({ password: newPassword });
      if (error) throw error;
      setPasswordMsg("Password changed successfully!");
      setNewPassword("");
    } catch (err: unknown) {
      setPasswordMsg(`Failed to update: ${err.message}`);
    } finally {
      setSavingPassword(false);
    }
  };

  const loadRazorpayScript = () => {
    return new Promise((resolve) => {
      const script = document.createElement("script");
      script.src = "https://checkout.razorpay.com/v1/checkout.js";
      script.onload = () => resolve(true);
      script.onerror = () => resolve(false);
      document.body.appendChild(script);
    });
  };

  const handleUpgrade = async () => {
    try {
      setUpgrading(true);

      const res = await loadRazorpayScript();
      if (!res) {
        alert("Razorpay SDK failed to load. Are you online?");
        return;
      }

      // We pass the user id as the client id for now, 
      // but in a fully operational CRM, this would map to their client record.
      const orderRes = await fetch("/api/payment", { 
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "create", clientId: user.id })
      });

      const json = await orderRes.json();

      if (!orderRes.ok || !json.success) {
        alert(json.message || "Failed to create order. Please check payment gateway configuration.");
        return;
      }

      const options = {
        key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID || "",
        amount: json.data.amount,
        currency: json.data.currency,
        name: "VANIKARA",
        description: "PRO Membership Upgrade",
        order_id: json.data.id,
        handler: async function (response: unknown) {
          const verifyRes = await fetch("/api/payment", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              action: "verify",
              razorpay_order_id: response.razorpay_order_id,
              razorpay_payment_id: response.razorpay_payment_id,
              razorpay_signature: response.razorpay_signature
            })
          });
          const verifyJson = await verifyRes.json();
          if (verifyJson.success) {
            setSub(verifyJson.data);
            alert("Payment successful! You are now a PRO member.");
          } else {
            alert("Payment verification failed.");
          }
        },
        prefill: {
          name: profile?.name || user?.email || "",
          email: user?.email || "",
        },
        theme: {
          color: "#4f46e5"
        }
      };

      const paymentObject = new (window as unknown).Razorpay(options);
      paymentObject.open();

    } catch (err) {
      console.error("Upgrade failed:", err);
      alert("Payment service unavailable.");
    } finally {
      setUpgrading(false);
    }
  };

  const trialDays = (() => {
    if (!sub?.trial_end) return 0;
    const diff = new Date(sub.trial_end).getTime() - Date.now();
    return Math.max(0, Math.ceil(diff / (1000 * 60 * 60 * 24)));
  })();

  const isExpired = sub?.plan === "free" && trialDays <= 0;

  const tabs = [
    { id: "overview", label: "Overview", icon: Compass },
    { id: "profile", label: "Profile Details", icon: User },
    { id: "chats", label: "Saved AI Chats", icon: MessageSquare },
    { id: "settings", label: "Settings", icon: Settings },
    { id: "notifications", label: "Notifications", icon: Bell },
    { id: "account", label: "Account Info", icon: Info },
    { id: "security", label: "Security & Lock", icon: Lock }
  ];

