  BarChart, Bar, PieChart, Pie, Cell, Legend
} from 'recharts';

interface ChartProps {
  leadsData: unknown[];
  revenueData: unknown[];
  conversionData: unknown[];
}

const COLORS = ['#1E6BD6', '#FF7A00', '#FFC400', '#10b981'];

export default function CRMCharts({ leadsData, revenueData, conversionData }: ChartProps) {
  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-12">
      {/* Leads Chart */}
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-black text-slate-900 mb-6 uppercase tracking-tight">Leads Over Time</h3>
        <div className="h-72 w-full relative">
          {(!leadsData || leadsData.length === 0) && (
            <div className="absolute inset-0 z-10 flex items-center justify-center bg-white/60 backdrop-blur-[1px]">
              <div className="px-4 py-2 bg-slate-100 rounded-lg border border-slate-200 text-xs font-bold text-slate-500 uppercase tracking-widest shadow-sm">
                No data available yet
              </div>
            </div>
          )}
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={leadsData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fontSize: 10, fill: '#94a3b8' }} />
              <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fill: '#94a3b8' }} />
              <Tooltip 
                contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }}
              />
              <Line type="monotone" dataKey="count" stroke="#1E6BD6" strokeWidth={3} dot={{ r: 4, fill: '#1E6BD6' }} activeDot={{ r: 6 }} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Revenue Chart */}
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-black text-slate-900 mb-6 uppercase tracking-tight">Revenue Analytics</h3>
        <div className="h-72 w-full relative">
          {(!revenueData || revenueData.length === 0) && (
            <div className="absolute inset-0 z-10 flex items-center justify-center bg-white/60 backdrop-blur-[1px]">
              <div className="px-4 py-2 bg-slate-100 rounded-lg border border-slate-200 text-xs font-bold text-slate-500 uppercase tracking-widest shadow-sm">
                No data available yet
              </div>
            </div>
          )}
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={revenueData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fontSize: 10, fill: '#94a3b8' }} />
              <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fill: '#94a3b8' }} />
              <Tooltip 
                contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }}
              />
              <Bar dataKey="amount" fill="#1E6BD6" radius={[6, 6, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Conversion Chart */}
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm lg:col-span-2">
        <h3 className="text-lg font-black text-slate-900 mb-6 uppercase tracking-tight">Conversion Funnel</h3>
        <div className="h-72 w-full flex flex-col md:flex-row items-center gap-8 relative">
          {(!conversionData || conversionData.length === 0) && (
            <div className="absolute inset-0 z-10 flex items-center justify-center bg-white/60 backdrop-blur-[1px]">
              <div className="px-4 py-2 bg-slate-100 rounded-lg border border-slate-200 text-xs font-bold text-slate-500 uppercase tracking-widest shadow-sm">
                No data available yet
              </div>
            </div>
          )}
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={conversionData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {conversionData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
              <Legend verticalAlign="middle" align="right" layout="vertical" />
            </PieChart>
          </ResponsiveContainer>
          <div className="grid grid-cols-2 gap-4 w-full md:w-1/2">
            {conversionData.map((item, _idx) => (
              <div key={item.name} className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <p className="text-[10px] font-black uppercase text-slate-400 mb-1">{item.name}</p>
                <p className="text-xl font-black text-slate-900">{item.value}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Briefcase, Mail, CheckCircle, XCircle, RefreshCw } from "lucide-react";
import Card, { CardBody } from "@/components/ui/Card";


export default function CareersManager() {
  const [candidates, setCandidates] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [positionFilter, setPositionFilter] = useState("all");
  const [notes, setNotes] = useState<Record<string, string>>({});

  // Load notes on mount
  useEffect(() => {
    if (typeof window !== "undefined") {
      const stored = localStorage.getItem("vanikara_candidate_notes");
      if (stored) {
        try {
          setNotes(JSON.parse(stored));
        } catch {
          setNotes({});
        }
      }
    }
  }, []);

  const handleSaveNote = (id: string, noteText: string) => {
    const updated = { ...notes, [id]: noteText };
    setNotes(updated);
    localStorage.setItem("vanikara_candidate_notes", JSON.stringify(updated));
  };

  const fetchCandidates = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/admin/careers");
      const json = await res.json();
      setCandidates(json.data || []);
    } catch (err) {
      console.error("Failed to fetch candidates:", err);
      setCandidates([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCandidates();
  }, []);

  const handleUpdateStatus = async (id: string, newStatus: string) => {
    try {
      setUpdatingId(id);
      const res = await fetch("/api/admin/careers", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id, status: newStatus })
      });
      if (res.ok) {
        fetchCandidates();
      }
    } catch (err) {
      console.error("Failed to update status:", err);
    } finally {
      setUpdatingId(null);
    }
  };

  const filteredCandidates = candidates.filter((cand) => {
    const matchesSearch = 
      cand.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      cand.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      cand.cover_letter?.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesPosition = 
      positionFilter === "all" || cand.position === positionFilter;

    return matchesSearch && matchesPosition;
  });

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-display font-black text-[var(--text-primary)] uppercase tracking-wider flex items-center gap-2">
          <Briefcase className="w-5 h-5 text-[var(--accent-color)]" />
          Careers & Internship Applications
        </h2>
        <p className="text-[10px] text-[var(--text-secondary)] font-bold uppercase mt-0.5">
          Review candidate resumes, statement letters, and shortlist candidates for interviews.
        </p>
      </div>

      {/* Search and Position Filters */}
      <div className="flex flex-col sm:flex-row gap-4 bg-[var(--glass-bg)] border border-[var(--glass-border)] p-4 rounded-3xl backdrop-blur-md select-none">
        <input
          type="text"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          placeholder="Search applicants by name, email, or statement text..."
          className="flex-grow px-4 py-2.5 bg-slate-500/5 border border-[var(--glass-border)] rounded-xl text-xs text-[var(--text-primary)] focus:outline-none focus:ring-1 focus:ring-[var(--accent-color)] font-semibold"
        />
        <select
          value={positionFilter}
          onChange={(e) => setPositionFilter(e.target.value)}
          className="px-4 py-2.5 bg-[var(--glass-bg)] border border-[var(--glass-border)] rounded-xl text-xs text-[var(--text-primary)] focus:outline-none focus:ring-1 focus:ring-[var(--accent-color)] font-semibold cursor-pointer"
        >
          <option value="all" className="bg-slate-900 text-white font-medium">All Positions</option>
          <option value="React Frontend Developer Intern" className="bg-slate-900 text-white font-medium">Frontend Intern</option>
          <option value="Node.js Fullstack Intern" className="bg-slate-900 text-white font-medium">Fullstack Intern</option>
          <option value="Campus Rep Coordinator" className="bg-slate-900 text-white font-medium">Campus Rep</option>
        </select>
      </div>

      <div className="space-y-4">
        {loading ? (
          <div className="p-8 text-center text-xs text-slate-500 flex justify-center items-center gap-2">
            <RefreshCw className="w-4 h-4 animate-spin text-[var(--accent-color)]" /> Fetching candidates...
          </div>
        ) : filteredCandidates.length === 0 ? (
          <div className="p-8 text-center text-xs text-slate-500 bg-[var(--glass-bg)] border border-[var(--glass-border)] rounded-3xl">
            No matching candidates found.
          </div>
        ) : (
          filteredCandidates.map((cand) => (
            <Card key={cand.id} hover>
              <CardBody className="p-6 sm:p-8 space-y-4">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 border-b border-[var(--glass-border)] pb-3 select-none">
                  <div>
                    <span className="text-[9px] font-black uppercase text-[var(--accent-color)] tracking-wider block">
                      {cand.position}
                    </span>
                    <h4 className="font-display font-black text-sm text-[var(--text-primary)] mt-0.5 uppercase">
                      {cand.name}
                    </h4>
                    <span className="text-[10px] text-slate-400 font-semibold flex items-center gap-1 mt-0.5">
                      <Mail className="w-3.5 h-3.5 text-[var(--accent-color)]" /> {cand.email}
                    </span>
                  </div>

                  <span className={`px-2.5 py-1 rounded text-[8px] font-black uppercase tracking-wider border ${
                    cand.status === "new"
                      ? "bg-blue-500/10 text-blue-500 border-blue-500/20"
                      : cand.status === "shortlisted"
                      ? "bg-green-500/10 text-green-500 border-green-500/20"
                      : "bg-red-500/10 text-red-500 border-red-500/20"
                  }`}>
                    {cand.status}
                  </span>
                </div>

                <div className="space-y-1.5 text-xs text-[var(--text-secondary)] leading-relaxed font-medium">
                  <strong>Statement of Intent / Cover Letter:</strong>
                  <p className="bg-slate-500/5 p-4 rounded-xl border border-[var(--glass-border)] whitespace-pre-wrap">
                    {cand.cover_letter || "No cover letter submitted."}
                  </p>
                </div>

                {/* Admin Evaluation Notes */}
                <div className="pt-4 border-t border-[var(--glass-border)] space-y-2">
                  <label className="block text-[9px] font-bold uppercase tracking-wider text-[var(--text-secondary)]">
                    Admin Evaluation Notes
                  </label>
                  <textarea
                    value={notes[cand.id] || ""}
                    onChange={(e) => handleSaveNote(cand.id, e.target.value)}
                    placeholder="Enter screening feedback, test scores, or background details..."
                    className="w-full h-20 p-3 bg-slate-500/5 border border-[var(--glass-border)] rounded-xl text-xs text-[var(--text-primary)] focus:outline-none focus:ring-1 focus:ring-[var(--accent-color)] resize-none font-medium placeholder:text-slate-500/40"
                  />
                </div>

                <div className="pt-2 flex justify-between items-center gap-4">
                  <div className="flex flex-wrap items-center gap-4 text-[9px] font-bold text-slate-400">
                    <span>Received: {new Date(cand.created_at || Date.now()).toLocaleDateString()}</span>
                    {cand.resume_url && (
                      <a 
                        href={cand.resume_url} 
                        target="_blank" 
                        rel="noopener noreferrer" 
                        className="text-[var(--accent-color)] hover:underline uppercase font-extrabold flex items-center gap-1 cursor-pointer"
                      >
                        📄 View Resume
                      </a>
                    )}
                  </div>

                  <div className="flex gap-2">
                    {cand.status !== "shortlisted" && (
                      <button
                        onClick={() => handleUpdateStatus(cand.id, "shortlisted")}
                        disabled={updatingId === cand.id}
                        className="px-3 py-1.5 bg-slate-500/5 hover:bg-green-500/15 border border-[var(--glass-border)] hover:border-green-500/20 rounded-lg text-[9px] font-black uppercase tracking-wider text-green-500 cursor-pointer flex items-center gap-1"
                      >
                        <CheckCircle className="w-3.5 h-3.5" /> Shortlist
                      </button>
                    )}
                    {cand.status !== "rejected" && (
                      <button
                        onClick={() => handleUpdateStatus(cand.id, "rejected")}
                        disabled={updatingId === cand.id}
                        className="px-3 py-1.5 bg-slate-500/5 hover:bg-red-500/15 border border-[var(--glass-border)] hover:border-red-500/20 rounded-lg text-[9px] font-black uppercase tracking-wider text-red-400 cursor-pointer flex items-center gap-1"
                      >
                        <XCircle className="w-3.5 h-3.5" /> Reject
                      </button>
                    )}
                  </div>
                </div>
              </CardBody>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {  Plus, Trash2 } from "lucide-react";

export default function PackagesManager() {
  const [packages, setPackages] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchPackages = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/packages");
      const json = await res.json();
      setPackages(json.data || []);
    } catch (err) {
      console.error("Failed to fetch packages:", err);
      setPackages([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPackages();
  }, []);

  const updatePackage = async (id: string, updates: unknown) => {
    try {
      await fetch("/api/packages", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id, ...updates })
      });
      fetchPackages();
    } catch (err) {
      console.error("Failed to update package:", err);
    }
  };

  if (loading) return <div className="p-12 text-center text-zinc-500">Loading packages...</div>;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      {(Array.isArray(packages) ? packages : []).map((pkg) => (
        <div key={pkg.id} className="bg-white border border-slate-200 rounded-3xl p-6 relative overflow-hidden group shadow-sm hover:border-blue-200 transition-all">
          <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 blur-3xl -mr-16 -mt-16 group-hover:bg-blue-600/10 transition-all duration-700"></div>

          <div className="flex justify-between items-center mb-6">
            <h3 className="text-xl font-bold text-slate-900 capitalize">{pkg.name}</h3>
            <span className="text-[10px] text-slate-400 font-mono italic">ID: {pkg.id.slice(0,8)}</span>
          </div>

          <div className="mb-6">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Monthly Pricing</label>
            <div className="flex items-center gap-2">
              <span className="text-2xl font-black text-slate-900">₹</span>
              <input 
                type="number" 
                value={pkg.price}
                onChange={(e) => updatePackage(pkg.id, { price: Number(e.target.value) })}
                className="bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 text-xl font-black text-slate-900 w-full focus:outline-none focus:border-blue-600 focus:bg-white transition-all shadow-inner"
              />
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Feature Set</label>
            <div className="space-y-3">
              {(Array.isArray(pkg.features) ? pkg.features : []).map((feature: string, idx: number) => (
                <div key={idx} className="flex items-center gap-3 bg-slate-50/50 p-2 rounded-xl border border-slate-100 group/item">
                  <div className="w-1.5 h-1.5 bg-blue-600 rounded-full shadow-sm shadow-blue-600/50"></div>
                  <input 
                    type="text" 
                    value={feature}
                    onChange={(e) => {
                      const newFeatures = [...(pkg.features || [])];
                      newFeatures[idx] = e.target.value;
                      updatePackage(pkg.id, { features: newFeatures });
                    }}
                    className="bg-transparent text-xs font-medium text-slate-600 w-full focus:outline-none focus:text-slate-900 transition-colors"
                  />
                  <button onClick={() => {
                     const newFeatures = (pkg.features || []).filter((_: unknown, i: number) => i !== idx);
                     updatePackage(pkg.id, { features: newFeatures });
                  }} className="text-slate-300 hover:text-red-600 transition-colors opacity-0 group-hover/item:opacity-100">
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              ))}
            </div>
          </div>

          <button 
            onClick={() => {
              const newFeatures = [...(pkg.features || []), "New Feature"];
              updatePackage(pkg.id, { features: newFeatures });
            }}
            className="w-full mt-8 py-3 bg-slate-900 hover:bg-blue-600 text-white rounded-2xl flex items-center justify-center gap-2 transition-all font-black uppercase tracking-widest text-[10px] shadow-sm shadow-slate-900/10 hover:shadow-blue-600/20 hover:scale-[1.02]"
          >
            <Plus className="w-4 h-4" /> Add Feature
          </button>
        </div>
      ))}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { ShoppingBag, Plus, Edit2, Trash2, Check, RefreshCw } from "lucide-react";
import Card, { CardBody } from "@/components/ui/Card";
import Button from "@/components/ui/Button";

export default function ProductsManager() {
  const [products, setProducts] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ id: "", name: "", category: "", description: "", availability: "concept" });
  const [isEditing, setIsEditing] = useState(false);
  const [saving, setSaving] = useState(false);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/admin/products");
      const json = await res.json();
      setProducts(json.data || []);
    } catch (err) {
      console.error("Failed to fetch products:", err);
      setProducts([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  const handleEdit = (p: unknown) => {
    setForm(p);
    setIsEditing(true);
  };

  const handleClear = () => {
    setForm({ id: "", name: "", category: "", description: "", availability: "concept" });
    setIsEditing(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const method = isEditing ? "PUT" : "POST";
      const res = await fetch("/api/admin/products", {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form)
      });
      if (res.ok) {
        handleClear();
        fetchProducts();
      }
    } catch (err) {
      console.error("Failed to save product:", err);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this product?")) return;
    try {
      const res = await fetch(`/api/admin/products?id=${id}`, {
        method: "DELETE"
      });
      if (res.ok) {
        fetchProducts();
      }
    } catch (err) {
      console.error("Failed to delete product:", err);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* List Products */}
      <div className="lg:col-span-7 space-y-6">
        <div>
          <h2 className="text-xl font-display font-black text-[var(--text-primary)] uppercase tracking-wider flex items-center gap-2">
            <ShoppingBag className="w-5 h-5 text-[var(--accent-color)]" />
            Ecosystem Products (CMS)
          </h2>
          <p className="text-[10px] text-[var(--text-secondary)] font-bold uppercase mt-0.5">
            Add or modify core company products and catalog structures.
          </p>
        </div>

        <div className="space-y-4">
          {loading ? (
            <div className="p-8 text-center text-xs text-slate-500 flex justify-center items-center gap-2">
              <RefreshCw className="w-4 h-4 animate-spin text-[var(--accent-color)]" /> Fetching products...
            </div>
          ) : products.length === 0 ? (
            <div className="p-8 text-center text-xs text-slate-500 bg-[var(--glass-bg)] border border-[var(--glass-border)] rounded-3xl">
              No products configured. Use the form to configure the first catalog item.
