"use client";

import React, { useRef, useState } from "react";
import { motion } from "framer-motion";

interface MagneticProps {
  children: React.ReactElement;
  range?: number;
}

export default function Magnetic({ children, _range = 50 }: MagneticProps) {
  const ref = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!ref.current) return;
    const { clientX, clientY } = e;
    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const centerX = left + width / 2;
    const centerY = top + height / 2;
    const dx = clientX - centerX;
    const dy = clientY - centerY;

    // Scale movement relative to distance
    setPosition({ x: dx * 0.35, y: dy * 0.35 });
  };

  const handleMouseLeave = () => {
    setPosition({ x: 0, y: 0 });
  };

  return (
    <motion.div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      animate={{ x: position.x, y: position.y }}
      transition={{ type: "spring", stiffness: 150, damping: 15, mass: 0.1 }}
      className="inline-block"
    >
      {children}
    </motion.div>
  );
}

"use client";

import React, { createContext, useContext, useState, useEffect } from "react";

export interface ConsentSettings {
  essential: boolean;
  preferences: boolean;
  analytics: boolean;
  marketing: boolean;
}

interface ConsentContextType {
  consent: ConsentSettings;
  hasSetConsent: boolean;
  showBanner: boolean;
  showModal: boolean;
  consentVersion: string;
  policyText: string;
  optionalServices: Record<string, boolean>;
  setShowBanner: (show: boolean) => void;
  setShowModal: (show: boolean) => void;
  acceptAll: () => void;
  rejectOptional: () => void;
  savePreferences: (prefs: Omit<ConsentSettings, "essential">) => void;
  openPreferences: () => void;
  closePreferences: () => void;
  refreshSettings: () => void;
}

const DEFAULT_CONSENT: ConsentSettings = {
  essential: true,
  preferences: false,
  analytics: false,
  marketing: false
};

const ConsentContext = createContext<ConsentContextType | undefined>(undefined);

export function ConsentProvider({ children }: { children: React.ReactNode }) {
  const [consent, setConsent] = useState<ConsentSettings>(DEFAULT_CONSENT);
  const [hasSetConsent, setHasSetConsent] = useState(false);
  const [showBanner, setShowBanner] = useState(false);
  const [showModal, setShowModal] = useState(false);

  // CMP Configs synced from the server configuration
  const [consentVersion, setConsentVersion] = useState("1.0.0");
  const [policyText, setPolicyText] = useState(
    "We use essential cookies to operate our website and optional cookies to improve performance, personalize your experience, and understand how visitors use our platform."
  );
  const [optionalServices, setOptionalServices] = useState<Record<string, boolean>>({
    googleAnalytics: true,
    facebookPixel: false,
    hotjar: false
  });

  // Load policy configurations and user preferences on mount
  const loadConsentData = async () => {
    // Immediately check local storage to prevent rendering delays
    const stored = localStorage.getItem("cookie_consent_settings");
    const storedVer = localStorage.getItem("cookie_consent_version");

    if (stored) {
      setConsent(JSON.parse(stored));
      setHasSetConsent(true);
      setShowBanner(false);
    } else {
      // Defer banner until first user interaction to prevent it from replacing the true LCP
      const triggerBanner = () => {
        setShowBanner(true);
        window.removeEventListener("scroll", triggerBanner);
        window.removeEventListener("touchstart", triggerBanner);
        window.removeEventListener("mousemove", triggerBanner);
        window.removeEventListener("keydown", triggerBanner);
      };

      window.addEventListener("scroll", triggerBanner, { passive: true });
      window.addEventListener("touchstart", triggerBanner, { passive: true });
      window.addEventListener("mousemove", triggerBanner, { passive: true });
      window.addEventListener("keydown", triggerBanner, { passive: true });
    }

    // Fetch latest policy version from the admin privacy API in the background
    try {
      const res = await fetch("/api/admin/privacy");
      if (res.ok) {
        const body = await res.json();
        if (body.success && body.data) {
          setConsentVersion(body.data.currentVersion);
          setPolicyText(body.data.policyText);
          setOptionalServices(body.data.optionalServices);

          // If they consented to an older version, we might want to re-trigger the banner
          // but for now we just update the text in case they open preferences.
          if (stored && storedVer !== body.data.currentVersion) {
            // Optional: trigger banner again for new version
            // setShowBanner(true); 
          }
        }
      }
    } catch (_e) {
      // Ignore background fetch errors
    }
  };

  useEffect(() => {
    loadConsentData();
  }, []);

  const persistConsent = async (settings: ConsentSettings, action: "accept_all" | "reject_optional" | "custom") => {
    setConsent(settings);
    setHasSetConsent(true);
    setShowBanner(false);
    setShowModal(false);

    // Save in local storage
    localStorage.setItem("cookie_consent_settings", JSON.stringify(settings));
    localStorage.setItem("cookie_consent_version", consentVersion);

    // Track consent update in database via API (updates stats anonymously)
    try {
      await fetch("/api/privacy/consent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action,
          preferences: settings,
          version: consentVersion
        })
      });
    } catch (_e) {
      // Fail silently (local state persists)
    }

    // Trigger standard analytics initialization rules dynamically
    if (settings.analytics) {
      // E.g. trigger ga('consent', 'update', { 'analytics_storage': 'granted' })
      (window as unknown).gtag?.("consent", "update", {
        analytics_storage: "granted"
      });
    } else {
      (window as unknown).gtag?.("consent", "update", {
        analytics_storage: "denied"
      });
    }
  };

  const acceptAll = () => {
    const allAccepted: ConsentSettings = {
      essential: true,
      preferences: true,
      analytics: true,
      marketing: true
    };
    persistConsent(allAccepted, "accept_all");
  };

  const rejectOptional = () => {
    const onlyEssential: ConsentSettings = {
      essential: true,
      preferences: false,
      analytics: false,
      marketing: false
    };
    persistConsent(onlyEssential, "reject_optional");
  };

  const savePreferences = (prefs: Omit<ConsentSettings, "essential">) => {
    const customSettings: ConsentSettings = {
      essential: true,
      ...prefs
    };
    persistConsent(customSettings, "custom");
  };

  const openPreferences = () => {
    setShowModal(true);
  };

  const closePreferences = () => {
    setShowModal(false);
  };

  return (
    <ConsentContext.Provider
      value={{
        consent,
        hasSetConsent,
        showBanner,
        showModal,
        consentVersion,
        policyText,
        optionalServices,
        setShowBanner,
        setShowModal,
        acceptAll,
        rejectOptional,
        savePreferences,
        openPreferences,
        closePreferences,
        refreshSettings: loadConsentData
      }}
    >
      {children}
    </ConsentContext.Provider>
  );
}

export function useConsent() {
  const context = useContext(ConsentContext);
  if (context === undefined) {
    throw new Error("useConsent must be used within a ConsentProvider");
  }
  return context;
}

"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import PWAInstallGuide from "@/components/layout/PWAInstallGuide";

interface PWAContextType {
  isInstallable: boolean;
  isInstalled: boolean;
  platform: "native" | "ios" | "unknown";
  showIOSInstructions: boolean;
  setShowIOSInstructions: (show: boolean) => void;
  installApp: () => Promise<boolean>;
}

const PWAContext = createContext<PWAContextType | undefined>(undefined);

export function PWAProvider({ children }: { children: React.ReactNode }) {
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [isInstalled, setIsInstalled] = useState(false);
  const [platform, setPlatform] = useState<"native" | "ios" | "unknown">("unknown");
  const [showIOSInstructions, setShowIOSInstructions] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;

    // Check if app is running in standalone mode (already installed PWA)
    const isStandalone = 
      window.matchMedia("(display-mode: standalone)").matches || 
      (window.navigator as unknown).standalone === true;

    if (isStandalone) {
      setIsInstalled(true);
      setIsInstallable(false);
      return;
    }

    // Determine platform
    const ua = navigator.userAgent;
    const isIOS = 
      /iPad|iPhone|iPod/.test(ua) || 
      (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1);

    if (isIOS) {
      setPlatform("ios");
      setIsInstallable(true); // iOS Safari can be added to home screen anytime
    } else {
      setPlatform("native");
    }

    // Check if a prompt was already captured by the layout head script
    if ((window as unknown).deferredPrompt) {
      setInstallPrompt((window as unknown).deferredPrompt);
      setIsInstallable(true);
      setPlatform("native");
    }

    // Listen to native beforeinstallprompt event
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e);
      setIsInstallable(true);
      setPlatform("native");
      (window as unknown).deferredPrompt = e;
    };

    // Listen to native appinstalled event
    const handleAppInstalled = () => {
      setIsInstalled(true);
      setIsInstallable(false);
      setInstallPrompt(null);
      (window as unknown).deferredPrompt = null;
    };

    window.addEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
    window.addEventListener("appinstalled", handleAppInstalled);

    // Development Debug overrides
    const params = new URLSearchParams(window.location.search);
    const debugParam = params.get("debug_pwa");
    const debugStorage = localStorage.getItem("debug_pwa");

    if (debugParam === "true" || debugStorage === "true") {
      setIsInstallable(true);
      const isIOSDebug = params.get("platform") === "ios" || localStorage.getItem("debug_pwa_platform") === "ios";
      setPlatform(isIOSDebug ? "ios" : "native");

      // Setup a mock native prompt if we are in native debug mode
      if (!isIOSDebug) {
        setInstallPrompt({
          prompt: () => {
          },
          userChoice: Promise.resolve({ outcome: "accepted" })
        });
      }
    }

    return () => {
      window.removeEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
      window.removeEventListener("appinstalled", handleAppInstalled);
    };
  }, []);

  const installApp = async () => {
    if (platform === "ios") {
      setShowIOSInstructions(true);
      return true;
    }

    if (!installPrompt) {
      console.warn("PWA installation is not available: no native install prompt stashed.");
      return false;
    }

    try {
      // Trigger the stashed install prompt
      await installPrompt.prompt();

      // Await user's install preference selection
      const { outcome } = await installPrompt.userChoice;

      // Clear the stashed prompt regardless of outcome to avoid calling prompt() on an exhausted object
      setInstallPrompt(null);
      setIsInstallable(false);
      (window as unknown).deferredPrompt = null;

      if (outcome === "accepted") {
        setIsInstalled(true);
        return true;
      }
    } catch (err) {
      console.error("PWA native installation failed:", err);
      // Ensure we clear state on error to avoid double prompt attempts crashing the site
      setInstallPrompt(null);
      setIsInstallable(false);
      (window as unknown).deferredPrompt = null;
    }

    return false;
  };

  return (
    <PWAContext.Provider
      value={{
        isInstallable,
        isInstalled,
        platform,
        showIOSInstructions,
        setShowIOSInstructions,
        installApp,
      }}
    >
      {children}
      <PWAInstallGuide
        isOpen={showIOSInstructions}
        onClose={() => setShowIOSInstructions(false)}
      />
    </PWAContext.Provider>
  );
}

export function usePWAContext() {
  const context = useContext(PWAContext);
  if (context === undefined) {
    throw new Error("usePWAContext must be used within a PWAProvider");
  }
  return context;
}

// @ts-expect-error isomorphic-dompurify has mismatched types sometimes
import DOMPurify from 'isomorphic-dompurify';

/**
 * Sanitize string to prevent XSS.
 */
export const sanitize = (str: string): string => {
  if (typeof str !== 'string') return '';
  return DOMPurify.sanitize(str.trim());
};

/**
 * Unified API response formatter.
 * Returns the actual user-facing error string passed to the function.
 * For security-sensitive contexts, callers should pass a safe message
 * rather than raw internal error details.
 */
export const apiResponse = (success: boolean, data: unknown = null, error: string | null = null) => {
  return { success, data, error };
};

/**
 * Structured error logging for server-side diagnostics.
 * Logs detailed context for developers without exposing secrets to clients.
 *
 * @param context   - Component or module name (e.g. "Stream Route", "OpenAI Provider")
 * @param error     - The error object or message string
 * @param metadata  - Optional structured fields for log correlation
 */
export const logError = (
  context: string,
  error: unknown,
  metadata?: {
    requestId?: string;
    model?: string;
    statusCode?: number;
    errorType?: string;
    userId?: string;
    latencyMs?: number;
  }
) => {
  const entry: Record<string, unknown> = {
    timestamp: new Date().toISOString(),
    context,
    message: error instanceof Error ? error.message : String(error),
  };

  if (error instanceof Error && error.stack) {
    entry.stack = error.stack;
  }

  if (metadata) {
    Object.assign(entry, metadata);
  }

  console.error(`[CYGMA][${entry.timestamp}][${context}]`, JSON.stringify(entry, null, 2));
};

/**
 * Structured info logging for non-error diagnostics.
 */
export const logInfo = (
  context: string,
  message: string,
  metadata?: Record<string, unknown>
) => {
  const entry: Record<string, unknown> = {
    timestamp: new Date().toISOString(),
    context,
    message,
    ...metadata,
  };

};

/**
 * Honeypot check.
 */
export const isBot = (honeypot: string): boolean => {
  return honeypot.length > 0;
};

"use client";

import { useState, FormEvent } from "react";
import { Send, CheckCircle2 } from "lucide-react";
import Button from "@/components/ui/Button";
import { logger } from "@/utils/logger";

export default function ContactForm() {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    company: "",
    subject: "",
    message: "",
    bot: ""
  });

  const [status, setStatus] = useState<"idle" | "sending" | "success">("idle");
  const [errors, setErrors] = useState<string | null>(null);

  const onSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (form.bot) return; // Silent reject for bots

    // Basic Validation
    if (!form.name.trim() || !form.email.trim() || !form.subject.trim() || !form.message.trim()) {
      setErrors("Please fill in all required fields.");
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(form.email)) {
      setErrors("Please enter a valid email address.");
      return;
    }

    if (form.name.length > 100) {
      setErrors("Name cannot exceed 100 characters.");
      return;
    }

    if (form.subject.length > 200) {
      setErrors("Subject cannot exceed 200 characters.");
      return;
    }

    if (form.message.length > 5000) {
      setErrors("Message cannot exceed 5000 characters.");
      return;
    }

    logger.form("Contact", "submit", form);
    setStatus("sending");
    setErrors(null);

    try {
      const response = await fetch("/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });

      let data: unknown = null;
      const contentType = response.headers.get("content-type");
      if (contentType && contentType.includes("application/json")) {
        try {
          data = await response.json();
        } catch (_jsonErr) {
          // Ignore json parse error here as we'll check response.ok next
        }
      }

      if (!response.ok) {
        throw new Error(data?.error || `Server Error (${response.status}). Please try again later.`);
      }

      logger.form("Contact", "success");
      setStatus("success");
    } catch (err: unknown) {
      logger.error("Failed to submit contact form", err);
      // Clean up raw JSON parser error tokens for user display
      const friendlyMsg = err.message.includes("is not valid JSON")
        ? "Server returned an invalid response. Please try again later."
        : err.message;
      setErrors(friendlyMsg || "Something went wrong. Please check fields and try again.");
      setStatus("idle");
    }
  };

  return (
    <div className="relative overflow-hidden rounded-[2.5rem] border border-[var(--glass-border)] bg-[var(--glass-bg)] backdrop-blur-md p-8 sm:p-10 shadow-xl">
      {/* Spotlight */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-[var(--accent-color)]/10 blur-[100px] rounded-full pointer-events-none -mr-32 -mt-32" />

      {status === "success" ? (
        <div className="relative z-10 text-center py-10 space-y-6 animate-in fade-in zoom-in-95 duration-500">
          <div className="w-16 h-16 bg-green-500/15 border border-green-500/30 rounded-2xl flex items-center justify-center mx-auto text-green-500">
            <CheckCircle2 className="w-8 h-8" />
          </div>
          <h3 className="font-display font-black text-2xl text-[var(--text-primary)]">
            Message Dispatched!
          </h3>
          <p className="text-xs text-[var(--text-secondary)] leading-relaxed max-w-sm mx-auto">
            Thank you! Your inquiry has been saved successfully and sent to the VANIKARA administration. We will review it and reply within 24 hours.
          </p>

          <div className="flex flex-col items-center gap-4 pt-4">
            <button
              onClick={() => {
                setStatus("idle");
                setForm({ name: "", email: "", phone: "", company: "", subject: "", message: "", bot: "" });
              }}
              className="text-[10px] font-black uppercase tracking-widest text-[var(--accent-color)] hover:underline cursor-pointer"
            >
              Submit Another Request
            </button>
          </div>
        </div>
      ) : (
        <form onSubmit={onSubmit} className="relative z-10 space-y-6">
          <div>
            <h2 className="font-display font-black text-2xl text-[var(--text-primary)] uppercase tracking-wider">
              Send a Message
            </h2>
            <p className="text-xs text-[var(--text-secondary)] mt-1">
              We respond to inquiries Monday through Friday.
            </p>
          </div>

          {errors && (
            <div className="p-4 bg-red-500/15 border border-red-500/30 text-red-500 rounded-xl text-xs font-bold text-center">
              {errors}
            </div>
          )}

          <div className="space-y-4">
            {/* Full Name */}
            <div className="relative">
              <input
                id="contact-name"
                type="text"
                required
                maxLength={100}
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="peer w-full px-4 pt-6 pb-2 bg-[var(--glass-bg)] border border-[var(--glass-border)] rounded-xl text-[var(--text-primary)] text-sm focus:outline-none focus:ring-2 focus:ring-[var(--accent-color)]/40 placeholder-transparent"
                placeholder="Full Name"
              />
              <label
                htmlFor="contact-name"
                className="absolute left-4 top-4.5 text-xs text-slate-500 transition-all pointer-events-none peer-placeholder-shown:text-sm peer-placeholder-shown:top-4 peer-focus:top-1.5 peer-focus:text-[10px] peer-focus:text-[var(--accent-color)] peer-focus:font-bold [:not(:placeholder-shown)]:top-1.5 [:not(:placeholder-shown)]:text-[10px] [:not(:placeholder-shown)]:text-[var(--accent-color)]"
              >
                Full Name *
              </label>
            </div>

            {/* Email Address */}
            <div className="relative">
              <input
                id="contact-email"
                type="email"
                required
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
                className="peer w-full px-4 pt-6 pb-2 bg-[var(--glass-bg)] border border-[var(--glass-border)] rounded-xl text-[var(--text-primary)] text-sm focus:outline-none focus:ring-2 focus:ring-[var(--accent-color)]/40 placeholder-transparent"
                placeholder="Email Address"
              />
