"use client";

import React, { useRef, useMemo } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { MeshTransmissionMaterial } from "@react-three/drei";
import { useCygmaWorld } from "@/context/CygmaWorldContext";
import { useTheme } from "@/components/layout/ThemeContext";
import { usePerformance } from "@/context/PerformanceContext";

// Seeded random number generator
function createSeededRandom(seed: number) {
  let s = seed;
  return function () {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

/**
 * AIPlanet: Renders the central Glass Sphere, internal basic glow nodes,
 * and internal refracted points.
 */
export default function AIPlanet() {
  const { resolvedTheme } = useTheme();
  const { view, sceneReady } = useCygmaWorld();
  const { config, _currentProfile } = usePerformance();
  const theme = resolvedTheme;
  const isDark = theme === "dark";

  const coreRef = useRef<THREE.Group>(null);
  const glowRef = useRef<THREE.Mesh>(null);
  const secondaryGlowRef = useRef<THREE.Mesh>(null);
  const innerParticlesRef = useRef<THREE.Points>(null);
  const glassSphereRef = useRef<THREE.Mesh>(null);
  const pointLightRef = useRef<THREE.PointLight>(null);

  // Dynamic tracking refs for smooth interpolations
  const currentGlassScale = useRef(1.0);
  const currentGlowScale = useRef(1.0);
  const currentParticlesScale = useRef(1.0);
  const currentGlowOpacity = useRef(1.0);
  const currentSecondaryGlowOpacity = useRef(1.0);
  const revealProgress = useRef(0);
  const interactedRef = useRef(false);

  React.useEffect(() => {
    if (typeof window !== "undefined" && window.innerWidth >= 768) {
      interactedRef.current = true;
      return;
    }
    const handleInteraction = () => {
      interactedRef.current = true;
      window.removeEventListener("pointerdown", handleInteraction);
      window.removeEventListener("scroll", handleInteraction);
      window.removeEventListener("touchstart", handleInteraction);
    };
    window.addEventListener("pointerdown", handleInteraction, { passive: true });
    window.addEventListener("scroll", handleInteraction, { passive: true });
    window.addEventListener("touchstart", handleInteraction, { passive: true });
    return () => {
      window.removeEventListener("pointerdown", handleInteraction);
      window.removeEventListener("scroll", handleInteraction);
      window.removeEventListener("touchstart", handleInteraction);
    };
  }, []);

  // Generate a cluster of neural particles inside the glass core
  const innerParticleCount = 80;
  const [particlePositions] = useMemo(() => {
    const rand = createSeededRandom(12345);
    const pos = new Float32Array(innerParticleCount * 3);
    for (let i = 0; i < innerParticleCount; i++) {
      const u = rand();
      const v = rand();
      const theta = u * 2.0 * Math.PI;
      const phi = Math.acos(2.0 * v - 1.0);
      const r = Math.cbrt(rand()) * 0.78;

      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      pos[i * 3 + 2] = r * Math.cos(phi);
    }
    return [pos];
  }, [innerParticleCount]);

  const throttleClock = useRef(0);

  useFrame((state, delta) => {
    // 1. Keep fully hidden and locked until scene graph compiles
    if (!sceneReady) {
      if (coreRef.current) {
        coreRef.current.scale.set(0, 0, 0);
      }
      revealProgress.current = 0;
      return;
    }

    const targetFps = config.targetFps || 60;
    const fpsLimit = 1 / targetFps;
    throttleClock.current += delta;
    if (throttleClock.current < fpsLimit) return;
    const throttledDelta = throttleClock.current;
    throttleClock.current = throttleClock.current % fpsLimit;

    // Advance reveal progress (over 3.0s total, fading in over first 1.5s)
    if (revealProgress.current < 3.0) {
      revealProgress.current = Math.min(3.0, revealProgress.current + throttledDelta);
    }

    const timeSinceReady = revealProgress.current;
    const revealOpacity = Math.min(1.0, timeSinceReady / 1.5);
    const time = state.clock.getElapsedTime();

    // Easing the scale from 0 to 1 over the 1.5s reveal
    const c1 = 1.70158;
    const c3 = c1 + 1;
    const easeOutBack = revealOpacity === 1 ? 1 : 1 + c3 * Math.pow(revealOpacity - 1, 3) + c1 * Math.pow(revealOpacity - 1, 2);
    let scale = easeOutBack;

    // Shrink scale to fade planet out during camera success pass-through
    if (view === "success") {
      scale = THREE.MathUtils.lerp(scale, 0, 0.035 * Math.min(3.0, throttledDelta / 0.0166));
    }

    if (coreRef.current) {
      // Scale is modulated by reveal progress
      coreRef.current.scale.set(scale, scale, scale);
      coreRef.current.rotation.y = time * 0.03 * config.orbitSpeedMult; // Slowed down by ~60%
      coreRef.current.rotation.x = 0;
      coreRef.current.position.y = 0.2;
    }

    // Dynamic targets based on active view preset
    let targetGlassScale = 1.0;
    let targetGlowScale = 1.0;
    let targetParticlesScale = 1.0;

    const defaultGlowOpacity = isDark ? 0.75 : 0.5;
    const defaultSecondaryOpacity = 0.3;
    let targetGlowOpacity = defaultGlowOpacity;
    let targetSecondaryOpacity = defaultSecondaryOpacity;

    if (view === "success") {
      targetGlassScale = 0.0;
      targetGlowScale = 0.0;
      targetParticlesScale = 0.0;
      targetGlowOpacity = 0.0;
      targetSecondaryOpacity = 0.0;
    } else if (view === "ai") {
      targetGlassScale = 4.2;
      targetGlowScale = 0.15;
      targetGlowOpacity = 0.01;
      targetSecondaryOpacity = 0.005;
      targetParticlesScale = 2.4;
    }

    const lerpSpeed = Math.min(1.0, 0.06 * (delta / 0.0166) * config.orbitSpeedMult);
    currentGlassScale.current = THREE.MathUtils.lerp(currentGlassScale.current, targetGlassScale, lerpSpeed);
    currentGlowScale.current = THREE.MathUtils.lerp(currentGlowScale.current, targetGlowScale, lerpSpeed);
    currentParticlesScale.current = THREE.MathUtils.lerp(currentParticlesScale.current, targetParticlesScale, lerpSpeed);
    currentGlowOpacity.current = THREE.MathUtils.lerp(currentGlowOpacity.current, targetGlowOpacity, lerpSpeed);
    currentSecondaryGlowOpacity.current = THREE.MathUtils.lerp(currentSecondaryGlowOpacity.current, targetSecondaryOpacity, lerpSpeed);

    if (glassSphereRef.current) {
      const gs = currentGlassScale.current;
      glassSphereRef.current.scale.set(gs, gs, gs);
      if (glassSphereRef.current.material && !Array.isArray(glassSphereRef.current.material)) {
        const mat = glassSphereRef.current.material as THREE.Material;
        mat.transparent = true;
        mat.opacity = revealOpacity;
      }
    }

    if (glowRef.current) {
      const pulseRate = view === "success" ? 6.0 : 1.2; // Softer breathing rate
      const pulseAmp = view === "success" ? 0.15 : 0.03; // Softer breathing amplitude
      // Multi-frequency pulse for organic breathing
      const organicPulse = (Math.sin(time * pulseRate * config.orbitSpeedMult) + Math.sin(time * pulseRate * 0.43) * 0.4) * pulseAmp;
      const pulse = (1.0 + organicPulse) * currentGlowScale.current;

      glowRef.current.scale.set(pulse, pulse, pulse);
      if (glowRef.current.material && !Array.isArray(glowRef.current.material)) {
        (glowRef.current.material as THREE.Material).opacity = currentGlowOpacity.current * revealOpacity;
      }
    }

    if (secondaryGlowRef.current) {
      const s = currentGlowScale.current * 1.05;
      secondaryGlowRef.current.scale.set(s, s, s);
      if (secondaryGlowRef.current.material && !Array.isArray(secondaryGlowRef.current.material)) {
        (secondaryGlowRef.current.material as THREE.Material).opacity = currentSecondaryGlowOpacity.current * revealOpacity;
      }
    }

    if (innerParticlesRef.current) {
      const ps = currentParticlesScale.current;
      innerParticlesRef.current.scale.set(ps, ps, ps);

      if (!innerParticlesRef.current.userData.time) {
        innerParticlesRef.current.userData.time = 0;
      }
      if (timeSinceReady >= 1.5 && interactedRef.current) {
        innerParticlesRef.current.userData.time += delta;
      }
      const activePTime = innerParticlesRef.current.userData.time;

      innerParticlesRef.current.rotation.y = -activePTime * 0.05 * config.orbitSpeedMult; // Organic slow rotation
      innerParticlesRef.current.rotation.x = activePTime * 0.02 * config.orbitSpeedMult;
      if (innerParticlesRef.current.material && !Array.isArray(innerParticlesRef.current.material)) {
        (innerParticlesRef.current.material as THREE.Material).opacity = (isDark ? 0.95 : 0.65) * revealOpacity;
      }
    }

    if (pointLightRef.current) {
      const baseIntensity = isDark ? 2.0 : 1.4;
      pointLightRef.current.intensity = baseIntensity * revealOpacity;
    }
  });

  const primaryGlowColor = isDark ? "#3b82f6" : "#0284c7"; // Sky blue vs brand blue
  const accentGlowColor = isDark ? "#a855f7" : "#ea580c";  // Purple highlights vs Sunset Orange
  const sphereColor = isDark ? "#1e1b4b" : "#bde0fe";      // Indigo glass core vs Translucent sky-blue glass core

  return (
    <group ref={coreRef}>
      {/* Internal point light inside the crystal sphere */}
      <pointLight 
        ref={pointLightRef}
        color={isDark ? "#60a5fa" : "#e0f2fe"} 
        intensity={0} 
        distance={5.0} 
        decay={1.8}
      />

      {/* A. Core Base Glow Node */}
      <mesh ref={glowRef}>
        <sphereGeometry args={[0.7, 32, 32]} />
        <meshBasicMaterial
          color={primaryGlowColor}
          transparent
          opacity={0}
          blending={THREE.AdditiveBlending}
        />
      </mesh>

      {/* B. Secondary Inner Contrast Glow */}
      <mesh ref={secondaryGlowRef} scale={[1.05, 1.05, 1.05]}>
        <sphereGeometry args={[0.48, 24, 24]} />
        <meshBasicMaterial
          color={accentGlowColor}
          transparent
          opacity={0}
          blending={THREE.AdditiveBlending}
        />
      </mesh>

      {/* C. Internal Neural Star Particles */}
      <points ref={innerParticlesRef}>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            args={[particlePositions, 3]}
          />
        </bufferGeometry>
        <pointsMaterial
          size={0.038}
          color={isDark ? "#e2e8f0" : "#0f172a"}
          transparent
          opacity={0}
          sizeAttenuation
          depthWrite={false}
          blending={isDark ? THREE.AdditiveBlending : THREE.NormalBlending}
        />
      </points>

      {/* D. Main Glass Core Sphere */}
      <mesh ref={glassSphereRef}>
        <icosahedronGeometry args={[1.22, 3]} />
        {config.useHeavyTransmission ? (
          <MeshTransmissionMaterial
            transmission={0.98}
            roughness={isDark ? 0.02 : 0.04}
            thickness={isDark ? 0.85 : 1.8}
            distortion={0.12}
            temporalDistortion={0.04}
            chromaticAberration={isDark ? 1.1 : 1.45}
            anisotropicBlur={0.15}
            ior={isDark ? 1.72 : 1.68} // Higher refractive index for rich refractions in both modes
            color={sphereColor}
            backside={true}
            transmissionSampler={true}
            transparent
            opacity={0}
          />
        ) : (
          <meshPhysicalMaterial
            transmission={0.9}
            roughness={isDark ? 0.05 : 0.1}
            thickness={isDark ? 0.85 : 1.5}
            ior={isDark ? 1.5 : 1.45}
            color={sphereColor}
            transparent
            opacity={0}
            depthWrite={false}
          />
        )}
      </mesh>
    </group>
  );
}

"use client";

import { useRef } from "react";
import { useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { useCygmaWorld } from "@/context/CygmaWorldContext";

/**
 * CameraController: Smoothly dollys, orbits, breathes, and pans the camera
 * between the various coordinates defined by our route perspectives.
 */
export default function CameraController() {
  const { view, sceneReady } = useCygmaWorld();
  const { camera, size } = useThree();

  const currentPos = useRef(new THREE.Vector3(0, 1.2, 14));
  const currentLookAt = useRef(new THREE.Vector3(0, 0.2, 0));
  const targetPosRef = useRef(new THREE.Vector3());
  const targetLookRef = useRef(new THREE.Vector3());
  const revealProgress = useRef(0);

  useFrame((state, delta) => {
    // 1. Lock camera in starting position until scene is compiled and ready
    if (!sceneReady) {
      camera.position.set(0, 1.2, 14);
      camera.lookAt(0, 0.2, 0);
      currentPos.current.set(0, 1.2, 14);
      currentLookAt.current.set(0, 0.2, 0);
      revealProgress.current = 0;
      return;
    }

    // Advance reveal progress (over 3.0 seconds total: 1.5s fade, 1.5s push)
    if (revealProgress.current < 3.0) {
      revealProgress.current = Math.min(3.0, revealProgress.current + delta);
    }
    const time = revealProgress.current;

    // Coordinated phases:
    // Phase 1: 0.0s to 1.5s -> Opacity Fade (camera remains static at starting Z=14 position)
    // Phase 2: 1.5s to 3.0s -> Camera Push (pushes from starting Z=14/Y=1.2 to target coordinates)
    const pushProgress = Math.min(1.0, Math.max(0.0, (time - 1.5) / 1.5));
    const idleActive = time >= 3.0;

    const pointer = state.pointer; // Mouse position normalized [-1, 1]
    const aspect = size.width / size.height;
    const scrollOffset = typeof window !== "undefined" ? window.scrollY : 0;

    // Viewport Detection
    const isMobile = size.width < 768;
    const isTabletPortrait = size.width >= 768 && size.width < 1024 && aspect < 1;
    const isTabletLandscape = size.width >= 768 && size.width < 1024 && aspect >= 1;
    const isTablet = isTabletPortrait || isTabletLandscape;
    const isDesktop = size.width >= 1024;

    // Responsive aspect multiplier
    const aspectModifier = aspect < 1 ? 1.0 + (1.0 - aspect) * 0.8 : 1.0;

    let targetX = 0;
    let targetY = 0.4;
    let targetZ = 7.5 * aspectModifier;
    const targetLookX = 0;
    let targetLookY = 0.2;
    let targetLookZ = 0;

    let useOrbitDrift = false;
    let useMouseParallax = false;
    let orbitScaleX = 0.3;
    let orbitScaleY = 0.2;
    let parallaxScaleX = 0.55;
    let parallaxScaleY = 0.45;

    // Define route-based target parameters
    switch (view) {
      case "hero":
        if (isMobile) {
          targetX = 0;
          targetY = -0.35;
          targetZ = 10.5;
          targetLookY = -0.35;
        } else if (isTabletPortrait) {
          targetX = 0;
          targetY = 0.2;
          targetZ = 9.5;
          targetLookY = 0.2;
        } else if (isTabletLandscape) {
          targetX = 0;
          targetY = 0.3;
          targetZ = 8.5;
          targetLookY = 0.2;
        } else {
          // Desktop
          targetX = 0;
          targetY = 0.4;
          targetZ = 7.5 * aspectModifier;
          targetLookY = 0.2;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;

        // Apply scroll offsets for scrollytelling depth
        const scrollZ = scrollOffset * (isMobile ? 0.003 : isTablet ? 0.0035 : 0.004);
        const scrollYOffset = -scrollOffset * (isMobile ? 0.0025 : isTablet ? 0.003 : 0.0035);
        targetZ += scrollZ;
        targetY += scrollYOffset;
        targetLookY += scrollYOffset * 0.25;
        break;

      case "about":
        if (isMobile) {
          targetX = 0;
          targetY = 1.2;
          targetZ = 9.5;
          targetLookY = 0.2;
        } else {
          targetX = 5.2 * aspectModifier;
          targetY = 1.0;
          targetZ = 5.2 * aspectModifier;
          targetLookY = 0.2;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = isMobile ? 0.08 : 0.2;
        orbitScaleY = isMobile ? 0.05 : 0.15;
        parallaxScaleX = 0.3;
        parallaxScaleY = 0.25;

        // About has timeline scroll tracking
        const aboutScrollY = -scrollOffset * (isMobile ? 0.002 : 0.003);
        targetY += aboutScrollY;
        targetLookY += aboutScrollY * 0.2;
        break;

      case "projects":
        if (isMobile) {
          targetX = 0;
          targetY = -4.2;
          targetZ = 7.5;
          targetLookY = 0.3;
        } else {
          targetX = 0;
          targetY = -4.5;
          targetZ = 4.8 * aspectModifier;
          targetLookY = 0.4;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = isMobile ? 0.05 : 0.15;
        orbitScaleY = isMobile ? 0.04 : 0.1;
        break;

      case "products":
        if (isMobile) {
          targetX = 0;
          targetY = 1.4;
          targetZ = 9.0;
          targetLookY = 0.2;
        } else {
          targetX = -4.8 * aspectModifier;
          targetY = 2.4;
          targetZ = 5.2 * aspectModifier;
          targetLookY = 0.2;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = isMobile ? 0.06 : 0.18;
        orbitScaleY = isMobile ? 0.04 : 0.12;
        break;

      case "ai":
        if (isMobile) {
          targetX = 0;
          targetY = 0.2;
          targetZ = 0.55;
          targetLookY = 0.2;
          targetLookZ = -2.5;
        } else {
          targetX = 0;
          targetY = 0.2;
          targetZ = 0.25;
          targetLookY = 0.2;
          targetLookZ = -3.0;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = 0.04;
        orbitScaleY = 0.03;
        parallaxScaleX = 0.08;
        parallaxScaleY = 0.06;
        break;

      case "login":
        if (isMobile) {
          targetX = 0;
          targetY = 0.0;
          targetZ = 4.2;
          targetLookY = 0.0;
        } else {
          targetX = 0;
          targetY = 0.2;
          targetZ = 3.6 * aspectModifier;
          targetLookY = 0.2;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = 0.08;
        orbitScaleY = 0.05;
        parallaxScaleX = 0.15;
        parallaxScaleY = 0.12;
        break;

      case "dashboard":
      case "success":
        if (isMobile) {
          targetX = 0;
          targetY = 0.2;
          targetZ = -4.5;
          targetLookY = 0.2;
          targetLookZ = -6.0;
        } else {
          targetX = 0;
          targetY = 0.2;
          targetZ = -3.5 * aspectModifier;
          targetLookY = 0.2;
          targetLookZ = -7.0;
        }
        break;

      case "admin":
        if (isMobile) {
          targetX = 0;
          targetY = 1.2;
          targetZ = 6.0;
          targetLookY = 0.2;
        } else {
          targetX = -2.8 * aspectModifier;
          targetY = 2.2;
          targetZ = 4.8 * aspectModifier;
          targetLookY = 0.2;
        }

        useMouseParallax = !isMobile;
        parallaxScaleX = 0.2;
        parallaxScaleY = 0.15;
        break;

      case "careers":
        if (isMobile) {
          targetX = 0;
          targetY = -1.0;
          targetZ = 6.5;
          targetLookY = 0.2;
        } else {
          targetX = 2.8 * aspectModifier;
          targetY = -1.5;
          targetZ = 5.6 * aspectModifier;
          targetLookY = 0.2;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = isMobile ? 0.1 : 0.15;
        orbitScaleY = isMobile ? 0.08 : 0.1;
        break;

      case "contact":
        if (isMobile) {
          targetX = 0;
          targetY = -0.4;
          targetZ = 6.5;
          targetLookY = 0.1;
        } else {
          targetX = -3.8 * aspectModifier;
          targetY = -0.5;
          targetZ = 5.2 * aspectModifier;
          targetLookY = 0.2;
        }

        useOrbitDrift = true;
        useMouseParallax = !isMobile;
        orbitScaleX = isMobile ? 0.12 : 0.18;
        orbitScaleY = isMobile ? 0.08 : 0.12;
        break;

      default:
        break;
    }

    // 2. Cinematic push-in scaling: start further back on Z-axis and pull in as reveal progresses
    if (pushProgress < 1.0) {
      const startZ = 14 * aspectModifier;
      const startY = 1.2;
      targetZ = THREE.MathUtils.lerp(startZ, targetZ, pushProgress);
      targetY = THREE.MathUtils.lerp(startY, targetY, pushProgress);
    }

    // 3. Add slow breathing & organic pseudo-noise drift (active only after the push-in is complete)
    if (useOrbitDrift && idleActive) {
      const t = state.clock.getElapsedTime();

      // Multi-frequency pseudo-noise for non-repeating organic drift
      const noiseZ = (Math.sin(t * 0.2) + Math.sin(t * 0.31) * 0.5 + Math.sin(t * 0.13) * 0.25) * 0.05;
      targetZ += noiseZ;

      const noiseX = (Math.sin(t * 0.12) + Math.cos(t * 0.23) * 0.6) * orbitScaleX * 0.8;
      const noiseY = (Math.cos(t * 0.15) + Math.sin(t * 0.27) * 0.5) * orbitScaleY * 0.8;

      targetX += noiseX;
      targetY += noiseY;
    }

    if (useMouseParallax && idleActive) {
      targetX += pointer.x * parallaxScaleX;
      targetY += pointer.y * parallaxScaleY;
    }

    // 4. Easing parameters: slow, frame-rate independent exponential damping
    const speedFactor = (view === "success" || view === "dashboard") ? 5.0 : 2.5;
    const lerpFactor = 1.0 - Math.exp(-speedFactor * delta);

    targetPosRef.current.set(targetX, targetY, targetZ);
    targetLookRef.current.set(targetLookX, targetLookY, targetLookZ);

    currentPos.current.lerp(targetPosRef.current, lerpFactor);
    currentLookAt.current.lerp(targetLookRef.current, lerpFactor);

    camera.position.copy(currentPos.current);
    camera.lookAt(currentLookAt.current);
  });

  return null;
}

"use client";

import React, { useRef, useMemo, useEffect } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { useCygmaWorld } from "@/context/CygmaWorldContext";
import { useTheme } from "@/components/layout/ThemeContext";
import { usePerformance } from "@/context/PerformanceContext";

// Seeded random number generator for stability across re-renders
function createSeededRandom(seed: number) {
  let s = seed;
  return function () {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

interface ConstellationNode {
  type: "primary" | "secondary" | "micro";
  basePosition: THREE.Vector3;
  phase: number;
  speed: number;
  orbitRadius: number;
  size: number;
  opacity: number;
}

/**
 * NeuralNetwork: A premium, cinematic AI intelligence field.
 * Organized into three hierarchical depth layers (Primary, Secondary, Micro)
 * with a stable nearest-neighbor network topology, organic noise drift,
 * global breathing, and camera parallax.
 */
export default function NeuralNetwork({ nodeCount = 24 }) {
  const { resolvedTheme } = useTheme();
  const { view, sceneReady } = useCygmaWorld();
  const { config } = usePerformance();
  const isDark = resolvedTheme === "dark";
  const revealProgress = useRef(0);
  const activeTimeRef = useRef(0);
  const interactedRef = useRef(false);

  useEffect(() => {
    if (typeof window !== "undefined" && window.innerWidth >= 768) {
      interactedRef.current = true;
      return;
    }
    const handleInteraction = () => {
      interactedRef.current = true;
      window.removeEventListener("pointerdown", handleInteraction);
      window.removeEventListener("scroll", handleInteraction);
      window.removeEventListener("touchstart", handleInteraction);
    };
    window.addEventListener("pointerdown", handleInteraction, { passive: true });
    window.addEventListener("scroll", handleInteraction, { passive: true });
    window.addEventListener("touchstart", handleInteraction, { passive: true });
    return () => {
      window.removeEventListener("pointerdown", handleInteraction);
      window.removeEventListener("scroll", handleInteraction);
      window.removeEventListener("touchstart", handleInteraction);
    };
  }, []);

  const primaryPointsRef = useRef<THREE.Points>(null);
  const secondaryPointsRef = useRef<THREE.Points>(null);
  const microPointsRef = useRef<THREE.Points>(null);
  const lineRef = useRef<THREE.LineSegments>(null);

  // 1. Generate node data structure and precalculated stable connections in a single block
  const { allNodes, uniqueConnections, primaryCount, secondaryCount, microCount } = useMemo(() => {
    const rand = createSeededRandom(44444);
    const items: ConstellationNode[] = [];
    const centerX = 0;
    const centerY = 0.2;
    const centerZ = 0.0; // Concentric with the central glass planet core [0, 0.2, 0]

    // Scale node counts dynamically using active performance limits (range ~4 to 16)
    const scaleMult = nodeCount / 16;
    const pCount = Math.max(4, Math.round(10 * scaleMult));    // Primary: 8-12 base
    const sCount = Math.max(12, Math.round(50 * scaleMult));   // Secondary: 40-60 base
    const mCount = Math.max(24, Math.round(120 * scaleMult));  // Micro: 100-150 base

    // Layer 1: Primary Nodes (Core, closest, largest)
    for (let i = 0; i < pCount; i++) {
      const r = 2.4 + rand() * 0.4; // Shell radius: [2.4, 2.8] (outside the 1.22 radius core)
      const theta = rand() * Math.PI * 2.0;
      const cosPhi = -rand(); // Uniform hemispherical distribution (Z <= 0)
      const sinPhi = Math.sqrt(1.0 - cosPhi * cosPhi);

      const bx = r * sinPhi * Math.cos(theta) + centerX;
      const by = r * sinPhi * Math.sin(theta) + centerY;
      const bz = r * cosPhi + centerZ;

      items.push({
        type: "primary",
        basePosition: new THREE.Vector3(bx, by, bz),
        phase: rand() * Math.PI * 2.0,
        speed: 0.05 + rand() * 0.03,
        orbitRadius: 0.16 + rand() * 0.06,
        size: 0.22 + rand() * 0.04,
        opacity: 0.85 + rand() * 0.1,
      });
    }

    // Layer 2: Secondary Nodes (Middle grid, medium)
    for (let i = 0; i < sCount; i++) {
      const r = 2.9 + rand() * 0.9; // Shell radius: [2.9, 3.8]
      const theta = rand() * Math.PI * 2.0;
      const cosPhi = -rand();
      const sinPhi = Math.sqrt(1.0 - cosPhi * cosPhi);

      const bx = r * sinPhi * Math.cos(theta) + centerX;
      const by = r * sinPhi * Math.sin(theta) + centerY;
      const bz = r * cosPhi + centerZ;

      items.push({
        type: "secondary",
        basePosition: new THREE.Vector3(bx, by, bz),
        phase: rand() * Math.PI * 2.0,
        speed: 0.08 + rand() * 0.05,
        orbitRadius: 0.28 + rand() * 0.08,
        size: 0.09 + rand() * 0.02,
        opacity: 0.5 + rand() * 0.12,
      });
    }

    // Layer 3: Micro Nodes (Outer backdrop, details)
    for (let i = 0; i < mCount; i++) {
      const r = 3.9 + rand() * 1.3; // Shell radius: [3.9, 5.2]
      const theta = rand() * Math.PI * 2.0;
      const cosPhi = -rand();
      const sinPhi = Math.sqrt(1.0 - cosPhi * cosPhi);

      const bx = r * sinPhi * Math.cos(theta) + centerX;
      const by = r * sinPhi * Math.sin(theta) + centerY;
      const bz = r * cosPhi + centerZ;

      items.push({
        type: "micro",
        basePosition: new THREE.Vector3(bx, by, bz),
        phase: rand() * Math.PI * 2.0,
        speed: 0.03 + rand() * 0.02,
        orbitRadius: 0.1 + rand() * 0.04,
        size: 0.03 + rand() * 0.015,
        opacity: 0.2 + rand() * 0.1,
      });
    }

    // Find nearest neighbors relative to base coordinates
    const connections: { from: number; to: number }[] = [];

    const getNearestNeighbors = (
      nodeIndex: number,
      targetType: "primary" | "secondary" | "micro" | "all",
      maxConnections: number
    ) => {
      const node = items[nodeIndex];
      const candidates: { index: number; dist: number }[] = [];

      items.forEach((otherNode, idx) => {
        if (idx === nodeIndex) return;
        if (targetType !== "all" && otherNode.type !== targetType) return;

        const dist = node.basePosition.distanceTo(otherNode.basePosition);
        candidates.push({ index: idx, dist });
      });

      candidates.sort((a, b) => a.dist - b.dist);
      return candidates.slice(0, maxConnections).map((c) => c.index);
    };

    items.forEach((node, idx) => {
      if (node.type === "primary") {
        // Connect primary to 3-4 nearby secondary nodes
        const numConn = 3 + Math.floor(rand() * 2);
        const neighbors = getNearestNeighbors(idx, "secondary", numConn);
        neighbors.forEach((n) => connections.push({ from: idx, to: n }));
      } else if (node.type === "secondary") {
        // Connect secondary to 2 nearby secondary/primary nodes
        const numConn = 2;
        const neighbors = getNearestNeighbors(idx, "all", numConn).filter(
          (n) => items[n].type === "secondary" || items[n].type === "primary"
        );
        neighbors.slice(0, numConn).forEach((n) => connections.push({ from: idx, to: n }));
      } else if (node.type === "micro") {
        // Connect micro to 1 nearby micro/secondary node
        const numConn = 1;
        const neighbors = getNearestNeighbors(idx, "all", numConn).filter(
          (n) => items[n].type === "micro" || items[n].type === "secondary"
        );
        neighbors.slice(0, numConn).forEach((n) => connections.push({ from: idx, to: n }));
      }
    });

    // Remove bidirectional overlaps to optimize line draw calls
    const uniqueConnections: { from: number; to: number }[] = [];
    const seen = new Set<string>();

    connections.forEach((conn) => {
      const key = conn.from < conn.to ? `${conn.from}_${conn.to}` : `${conn.to}_${conn.from}`;
      if (!seen.has(key)) {
        seen.add(key);
        uniqueConnections.push(conn);
      }
    });

    return {
      allNodes: items,
      uniqueConnections,
      primaryCount: pCount,
      secondaryCount: sCount,
      microCount: mCount,
    };
  }, [nodeCount]);

  // 2. Pre-allocate typed arrays to prevent memory garbage collection overhead inside rendering loops
  const primaryPositions = useMemo(() => new Float32Array(primaryCount * 3), [primaryCount]);
  const secondaryPositions = useMemo(() => new Float32Array(secondaryCount * 3), [secondaryCount]);
  const microPositions = useMemo(() => new Float32Array(microCount * 3), [microCount]);

  const maxLineVertices = uniqueConnections.length * 2;
  const linePositions = useMemo(() => new Float32Array(maxLineVertices * 3), [uniqueConnections]);
  const lineColors = useMemo(() => new Float32Array(maxLineVertices * 3), [uniqueConnections]);

  const themeColor = useMemo(() => {
    return new THREE.Color(isDark ? "#4f46e5" : "#60a5fa");
  }, [isDark]);

  const activeCoords = useMemo(() => {
    return allNodes.map(() => new THREE.Vector3());
  }, [allNodes]);

  // 3. Render soft radial gradient textures for organic glowing nodes
  const circularTexture = useMemo(() => {
    if (typeof window === "undefined") return null;
    const canvas = document.createElement("canvas");
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext("2d");
    if (ctx) {
      ctx.clearRect(0, 0, 64, 64);
      const gradient = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
      gradient.addColorStop(0, "rgba(255, 255, 255, 1)");
      gradient.addColorStop(0.2, "rgba(255, 255, 255, 0.95)");
      gradient.addColorStop(0.5, "rgba(255, 255, 255, 0.3)");
      gradient.addColorStop(1, "rgba(255, 255, 255, 0)");
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(32, 32, 32, 0, Math.PI * 2);
      ctx.fill();
    }
    return new THREE.CanvasTexture(canvas);
  }, []);

  useEffect(() => {
    return () => {
      if (circularTexture) {
        circularTexture.dispose();
      }
    };
  }, [circularTexture]);

  const throttleClock = useRef(0);

  useFrame((state, delta) => {
    // A. Apply dynamic opacity checks and lock nodes before sceneReady compiles
    if (!sceneReady) {
      if (primaryPointsRef.current && primaryPointsRef.current.material && !Array.isArray(primaryPointsRef.current.material)) {
        (primaryPointsRef.current.material as THREE.Material).opacity = 0;
      }
      if (secondaryPointsRef.current && secondaryPointsRef.current.material && !Array.isArray(secondaryPointsRef.current.material)) {
        (secondaryPointsRef.current.material as THREE.Material).opacity = 0;
      }
      if (microPointsRef.current && microPointsRef.current.material && !Array.isArray(microPointsRef.current.material)) {
        (microPointsRef.current.material as THREE.Material).opacity = 0;
      }
      revealProgress.current = 0;
      return;
    }

    const targetFps = config.targetFps || 60;
    const fpsLimit = 1 / targetFps;
    throttleClock.current += delta;
    if (throttleClock.current < fpsLimit) return;
    const throttledDelta = throttleClock.current;
    throttleClock.current = throttleClock.current % fpsLimit;

    // Advance reveal progress (over 3.0s total, fading in over first 1.5s)
    if (revealProgress.current < 3.0) {
      revealProgress.current = Math.min(3.0, revealProgress.current + throttledDelta);
    }
    const timeSinceReady = revealProgress.current;
    const revealOpacity = Math.min(1.0, timeSinceReady / 1.5);

    // Active movement time only ticks after revealOpacity completes (1.5s) and user has interacted on mobile
    if (timeSinceReady >= 1.5 && interactedRef.current) {
      activeTimeRef.current += throttledDelta;
    }
    const activeTime = activeTimeRef.current;

    const pointer = state.pointer; // Mouse coords: [-1, 1]

    // B. Apply organic pseudo-noise drift, global breathing, and layer-based cursor parallax
    allNodes.forEach((node, i) => {
      const t = activeTime * node.speed * config.orbitSpeedMult * 0.5; // Slower orbital speed

      // Coherent slow floating displacement (organic noise)
      const dx = (Math.sin(t + node.phase) * 0.55 + Math.cos(t * 0.4 + node.phase * 2.3) * 0.45) * node.orbitRadius;
      const dy = (Math.cos(t * 0.6 + node.phase) * 0.55 + Math.sin(t * 0.3 + node.phase * 1.7) * 0.45) * node.orbitRadius;
      const dz = (Math.sin(t * 0.7 + node.phase * 1.5) * 0.55 + Math.cos(t * 0.5 + node.phase * 3.1) * 0.45) * node.orbitRadius;

      const currentPos = activeCoords[i];
      currentPos.set(
        node.basePosition.x + dx,
        node.basePosition.y + dy,
        node.basePosition.z + dz
      );

      // Global slow breathing cycle
      const breathTime = activeTime * 0.15;
      const breathScale = 1.0 + Math.sin(breathTime) * 0.035;
      currentPos.multiplyScalar(breathScale);

      // Parallax shifts based on node type depth (active only after push-in complete)
      if (timeSinceReady >= 3.0) {
        let parallaxFactor = 0.05;
        if (node.type === "primary") parallaxFactor = 0.03;
        else if (node.type === "secondary") parallaxFactor = 0.08;
        else if (node.type === "micro") parallaxFactor = 0.16;

        currentPos.x += pointer.x * parallaxFactor;
        currentPos.y += pointer.y * parallaxFactor;
      }
    });

    // C. Save displacements to flat buffer arrays grouped by hierarchical category
    let pIdx = 0;
    let sIdx = 0;
    let mIdx = 0;

    allNodes.forEach((node, i) => {
      const pos = activeCoords[i];
      if (node.type === "primary") {
        primaryPositions[pIdx * 3] = pos.x;
        primaryPositions[pIdx * 3 + 1] = pos.y;
        primaryPositions[pIdx * 3 + 2] = pos.z;
        pIdx++;
      } else if (node.type === "secondary") {
        secondaryPositions[sIdx * 3] = pos.x;
        secondaryPositions[sIdx * 3 + 1] = pos.y;
        secondaryPositions[sIdx * 3 + 2] = pos.z;
        sIdx++;
      } else if (node.type === "micro") {
        microPositions[mIdx * 3] = pos.x;
        microPositions[mIdx * 3 + 1] = pos.y;
        microPositions[mIdx * 3 + 2] = pos.z;
        mIdx++;
      }
    });

    // D. Trigger GPU attribute buffer updates safely
    if (primaryPointsRef.current && primaryPointsRef.current.geometry.attributes.position) {
      primaryPointsRef.current.geometry.attributes.position.needsUpdate = true;
    }
    if (secondaryPointsRef.current && secondaryPointsRef.current.geometry.attributes.position) {
      secondaryPointsRef.current.geometry.attributes.position.needsUpdate = true;
    }
    if (microPointsRef.current && microPointsRef.current.geometry.attributes.position) {
      microPointsRef.current.geometry.attributes.position.needsUpdate = true;
    }

    // E. Dynamically update point material opacities based on reveal progress
    if (primaryPointsRef.current && primaryPointsRef.current.material && !Array.isArray(primaryPointsRef.current.material)) {
      (primaryPointsRef.current.material as THREE.Material).opacity = (isDark ? 0.85 : 0.95) * revealOpacity;
    }
    if (secondaryPointsRef.current && secondaryPointsRef.current.material && !Array.isArray(secondaryPointsRef.current.material)) {
      (secondaryPointsRef.current.material as THREE.Material).opacity = (isDark ? 0.55 : 0.7) * revealOpacity;
    }
    if (microPointsRef.current && microPointsRef.current.material && !Array.isArray(microPointsRef.current.material)) {
      (microPointsRef.current.material as THREE.Material).opacity = (isDark ? 0.3 : 0.45) * revealOpacity;
    }

    // F. Compute connection segments using distance-based fading and animated flow intensity pulse
    const threshold = 4.2;
    let lineIdx = 0;

    uniqueConnections.forEach((conn) => {
      const posA = activeCoords[conn.from];
      const posB = activeCoords[conn.to];
      const dist = posA.distanceTo(posB);

      const nodeA = allNodes[conn.from];
      const nodeB = allNodes[conn.to];

      // Base line opacity matches the connection endpoints
      const baseOpacity = Math.min(nodeA.opacity, nodeB.opacity) * 0.4;
      const linePulse = 0.85 + Math.sin(activeTime * 1.8 + conn.from) * 0.15; // Animated flow energy
      const alpha = Math.max(0.0, 1.0 - dist / threshold) * baseOpacity * linePulse * revealOpacity;

      const rVal = themeColor.r * alpha;
      const gVal = themeColor.g * alpha;
      const bVal = themeColor.b * alpha;

      linePositions[lineIdx] = posA.x;
      linePositions[lineIdx + 1] = posA.y;
      linePositions[lineIdx + 2] = posA.z;
      lineColors[lineIdx] = rVal;
      lineColors[lineIdx + 1] = gVal;
      lineColors[lineIdx + 2] = bVal;

      linePositions[lineIdx + 3] = posB.x;
      linePositions[lineIdx + 4] = posB.y;
      linePositions[lineIdx + 5] = posB.z;
      lineColors[lineIdx + 3] = rVal;
      lineColors[lineIdx + 4] = gVal;
      lineColors[lineIdx + 5] = bVal;

      lineIdx += 6;
    });

    if (lineRef.current) {
      const geometry = lineRef.current.geometry;
      geometry.setDrawRange(0, lineIdx / 3);
      if (geometry.attributes.position) {
        geometry.attributes.position.needsUpdate = true;
      }
      if (geometry.attributes.color) {
        geometry.attributes.color.needsUpdate = true;
      }
    }
  });

  return (
    <group>
      {/* 1. Layer 1: Primary Nodes (Large Core Glowing Hubs) */}
      <points ref={primaryPointsRef}>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            args={[primaryPositions, 3]}
          />
        </bufferGeometry>
        <pointsMaterial
          size={0.24}
          color={isDark ? "#818cf8" : "#3b82f6"}
          transparent
          opacity={0}
          sizeAttenuation
          depthWrite={false}
          map={circularTexture || undefined}
          blending={isDark ? THREE.AdditiveBlending : THREE.NormalBlending}
        />
      </points>

      {/* 2. Layer 2: Secondary Nodes (Interconnected Network Grid) */}
      <points ref={secondaryPointsRef}>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            args={[secondaryPositions, 3]}
          />
        </bufferGeometry>
        <pointsMaterial
          size={0.11}
          color={isDark ? "#6366f1" : "#2563eb"}
          transparent
          opacity={0}
          sizeAttenuation
          depthWrite={false}
          map={circularTexture || undefined}
          blending={isDark ? THREE.AdditiveBlending : THREE.NormalBlending}
        />
      </points>

      {/* 3. Layer 3: Micro Nodes (Tiny Atmospheric Details) */}
      <points ref={microPointsRef}>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            args={[microPositions, 3]}
          />
        </bufferGeometry>
        <pointsMaterial
          size={0.038}
          color={isDark ? "#4f46e5" : "#60a5fa"}
          transparent
          opacity={0}
          sizeAttenuation
          depthWrite={false}
          map={circularTexture || undefined}
          blending={isDark ? THREE.AdditiveBlending : THREE.NormalBlending}
        />
      </points>

      {/* 4. Fine Connection Segments (Pulsing Energy Flow) */}
      {view !== "success" && (
        <lineSegments ref={lineRef}>
          <bufferGeometry>
            <bufferAttribute
              attach="attributes-position"
              args={[linePositions, 3]}
            />
            <bufferAttribute
              attach="attributes-color"
              args={[lineColors, 3]}
            />
          </bufferGeometry>
          <lineBasicMaterial
            vertexColors={true}
            transparent
            opacity={0}
            blending={isDark ? THREE.AdditiveBlending : THREE.NormalBlending}
          />
        </lineSegments>
      )}
    </group>
  );
}

"use client";

import React, { useRef, useMemo, useEffect } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { useCygmaWorld } from "@/context/CygmaWorldContext";
import { useTheme } from "@/components/layout/ThemeContext";
import { usePerformance } from "@/context/PerformanceContext";

// Seeded random number generator
function createSeededRandom(seed: number) {
  let s = seed;
  return function () {
    s = (s * 9301 + 49297) % 233280;
    return s / 233280;
  };
}

/**
 * ParticleField: Handles the 3D background floating particles.
 * Velocities scale up during auth success or dashboard view changes to simulate camera movement.
 */
export default function ParticleField({ count = 650 }) {
  const pointsRef = useRef<THREE.Points>(null);
  const { resolvedTheme } = useTheme();
  const { view, sceneReady } = useCygmaWorld();
  const { config } = usePerformance();

  const revealProgress = useRef(0);
  const activeTimeRef = useRef(0);
  const interactedRef = useRef(false);

  useEffect(() => {
    if (typeof window !== "undefined" && window.innerWidth >= 768) {
      interactedRef.current = true;
      return;
    }
    const handleInteraction = () => {
      interactedRef.current = true;
      window.removeEventListener("pointerdown", handleInteraction);
      window.removeEventListener("scroll", handleInteraction);
      window.removeEventListener("touchstart", handleInteraction);
    };
    window.addEventListener("pointerdown", handleInteraction, { passive: true });
    window.addEventListener("scroll", handleInteraction, { passive: true });
    window.addEventListener("touchstart", handleInteraction, { passive: true });
    return () => {
      window.removeEventListener("pointerdown", handleInteraction);
      window.removeEventListener("scroll", handleInteraction);
      window.removeEventListener("touchstart", handleInteraction);
    };
  }, []);

  // Generate deterministic coordinates
  const [positions, _speeds] = useMemo(() => {
    const rand = createSeededRandom(11111);
    const pos = new Float32Array(count * 3);
    const spd = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      pos[i * 3] = (rand() - 0.5) * 16;
      pos[i * 3 + 1] = (rand() - 0.5) * 11;
      pos[i * 3 + 2] = (rand() - 0.5) * 10 - 2;

      // Slow drift along the Z-axis
      spd[i * 3] = (rand() - 0.5) * 0.003;
      spd[i * 3 + 1] = (rand() - 0.5) * 0.003;
      spd[i * 3 + 2] = (rand() - 0.5) * 0.003 - 0.002;
    }
    return [pos, spd];
  }, [count]);

  const throttleClock = useRef(0);

  useFrame((state, delta) => {
    if (!pointsRef.current) return;

    if (!sceneReady) {
      revealProgress.current = 0;
      if (pointsRef.current.material && !Array.isArray(pointsRef.current.material)) {
        (pointsRef.current.material as THREE.Material).opacity = 0;
      }
      return;
    }

    const targetFps = config.targetFps || 60;
    const fpsLimit = 1 / targetFps;
    throttleClock.current += delta;
    if (throttleClock.current < fpsLimit) return;
    const throttledDelta = throttleClock.current;
    throttleClock.current = throttleClock.current % fpsLimit;

    if (revealProgress.current < 3.0) {
      revealProgress.current = Math.min(3.0, revealProgress.current + throttledDelta);
    }
    const timeSinceReady = revealProgress.current;
    const revealOpacity = Math.min(1.0, timeSinceReady / 1.5);

    if (timeSinceReady >= 1.5 && interactedRef.current) {
      activeTimeRef.current += throttledDelta;
    }
    const activeTime = activeTimeRef.current;

    // Warp factors: speeds multiply dynamically on success
    const warpMult = view === "success" ? 15.0 : 1.0;

    // Apply organic flow to the entire particle field
    pointsRef.current.rotation.y = activeTime * 0.015 * warpMult * config.orbitSpeedMult;
    pointsRef.current.rotation.x = activeTime * 0.005 * warpMult * config.orbitSpeedMult;

    // Subtle organic positional drift
    const driftX = Math.sin(activeTime * 0.2) * 0.15;
    const driftY = Math.cos(activeTime * 0.15) * 0.15;
    pointsRef.current.position.x = driftX;
    pointsRef.current.position.y = driftY;

    if (pointsRef.current.material && !Array.isArray(pointsRef.current.material)) {
      const baseOpacity = isDark ? 0.45 : 0.6;
      (pointsRef.current.material as THREE.Material).opacity = baseOpacity * revealOpacity;
    }
  });

  const isDark = resolvedTheme === "dark";
  const particleColor = isDark ? "#a5b4fc" : "#475569"; // Light lavender vs steel blue

  // Create a high-quality soft circular texture for rounded particles
  const circleTexture = useMemo(() => {
    if (typeof window === "undefined") return null;
    const canvas = document.createElement("canvas");
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext("2d");
    if (ctx) {
      ctx.clearRect(0, 0, 64, 64);
      // Soft radial gradient for a beautiful glow effect
      const gradient = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
      gradient.addColorStop(0, "rgba(255, 255, 255, 1)");
      gradient.addColorStop(0.25, "rgba(255, 255, 255, 0.85)");
      gradient.addColorStop(0.55, "rgba(255, 255, 255, 0.35)");
      gradient.addColorStop(1, "rgba(255, 255, 255, 0)");
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(32, 32, 32, 0, Math.PI * 2);
      ctx.fill();
    }
    const texture = new THREE.CanvasTexture(canvas);
    return texture;
  }, []);

  useEffect(() => {
    return () => {
      if (circleTexture) {
        circleTexture.dispose();
      }
    };
  }, [circleTexture]);

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          args={[positions, 3]}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.065}
        color={particleColor}
        transparent
        opacity={0}
        sizeAttenuation
        depthWrite={false}
        map={circleTexture || undefined}
        blending={isDark ? THREE.AdditiveBlending : THREE.NormalBlending}
      />
    </points>
  );
}
